/****** Object:  View [dbo].[vw_Report_OrderRevenue]    Script Date: 01/07/2026 12:47:25 SA ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/* =========================================================
   A. VIEW: Tong hop doanh thu theo don hang
   ========================================================= */
CREATE   VIEW [dbo].[vw_Report_OrderRevenue]
AS
SELECT
    O.Id,
    O.OrderCode,
    O.UserId,
    U.Email AS CustomerEmail,
    U.FullName AS CustomerFullName,
    O.OrderStatus,
    O.PaymentStatus,
    O.PaymentMethod,
    O.Subtotal,
    O.ShippingFee,
    O.DiscountAmount,
    O.TotalAmount,
    O.CreatedAt,
    O.UpdatedAt,
    O.Note,
    CASE
        WHEN O.OrderStatus IN (N'Completed', N'Shipping', N'Processing', N'Confirmed') THEN 1
        ELSE 0
    END AS IsRevenueOrder,
    CASE
        WHEN O.OrderStatus = N'Completed' THEN O.TotalAmount
        ELSE 0
    END AS CompletedRevenue,
    CASE
        WHEN O.PaymentStatus = N'Paid' THEN O.TotalAmount
        ELSE 0
    END AS PaidRevenue
FROM dbo.Orders O
LEFT JOIN dbo.AspNetUsers U
    ON U.Id = O.UserId;


