/****** Object:  View [dbo].[vw_Report_SalesDetail]    Script Date: 01/07/2026 12:47:25 SA ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/* =========================================================
   B. VIEW: Chi tiet ban hang theo dong san pham
   ========================================================= */
CREATE   VIEW [dbo].[vw_Report_SalesDetail]
AS
SELECT
    O.Id AS OrderId,
    O.OrderCode,
    O.CreatedAt AS OrderCreatedAt,
    O.OrderStatus,
    O.PaymentStatus,
    O.PaymentMethod,
    O.UserId,
    U.Email AS CustomerEmail,
    OI.Id AS OrderItemId,
    OI.ProductId,
    P.SKU,
    P.Name AS ProductName,
    P.CategoryId,
    C.Name AS CategoryName,
    P.BrandId,
    B.Name AS BrandName,
    OI.UnitPrice,
    OI.Quantity,
    OI.LineTotal
FROM dbo.OrderItems OI
INNER JOIN dbo.Orders O
    ON O.Id = OI.OrderId
INNER JOIN dbo.Products P
    ON P.Id = OI.ProductId
INNER JOIN dbo.Categories C
    ON C.Id = P.CategoryId
INNER JOIN dbo.Brands B
    ON B.Id = P.BrandId
LEFT JOIN dbo.AspNetUsers U
    ON U.Id = O.UserId;


