        ON PR.Id = PRI.PurchaseReceiptId
    GROUP BY
        P.Id, P.SKU, P.[Name], C.[Name], B.[Name]
)
SELECT
    X.*,
    DENSE_RANK() OVER (ORDER BY X.ImportedUnits DESC, X.ImportValue DESC, X.ProductId ASC) AS ImportRank
