INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (1, N'CPU-INTEL-CU5-245K', N'Bộ vi xử lý Intel Core Ultra 5 245K', N'bo-vi-xu-ly-intel-core-ultra-5-245k', 1, 1, CAST(8990000.00 AS Decimal(18, 2)), CAST(6690000.00 AS Decimal(18, 2)), 113, 5, N'CPU Intel Core Ultra 5 245K, 14 nhân 14 luồng, turbo up to 5.2GHz, socket LGA 1851.', N'Intel Core Ultra 5 245K là bộ vi xử lý thuộc dòng Intel Core Ultra thế hệ mới, hướng đến nhu cầu gaming, làm việc văn phòng nâng cao và sáng tạo nội dung ở mức bán chuyên. Sản phẩm sử dụng socket LGA 1851, có tổng cộng 14 nhân 14 luồng với cấu trúc gồm 6 P-core và 8 E-core, giúp cân bằng hiệu năng đơn nhân và đa nhiệm. CPU hỗ trợ RAM tốc độ cao lên đến 6400MHz, có đồ họa tích hợp, phù hợp cho người dùng muốn xây dựng cấu hình hiện đại, ổn định và có khả năng nâng cấp lâu dài.', N'/uploads/products/cpu/intel-core-ultra-5-245k/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), CAST(N'2026-04-07T15:05:27.3453720' AS DateTime2))
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (2, N'CPU-INTEL-CU7-265K', N'Bộ vi xử lý Intel Core Ultra 7 265K', N'bo-vi-xu-ly-intel-core-ultra-7-265k', 1, 1, CAST(11790000.00 AS Decimal(18, 2)), NULL, 112, 0, N'CPU Intel Core Ultra 7 265K, 20 nhân 20 luồng, turbo up to 5.5GHz, socket LGA 1851.', N'Intel Core Ultra 7 265K là lựa chọn mạnh mẽ cho game thủ cao cấp, streamer và người dùng làm việc đa nhiệm nặng. CPU sở hữu 20 nhân 20 luồng, gồm 8 P-core và 12 E-core, cho khả năng xử lý nhanh trong cả tác vụ đơn nhân lẫn đa luồng. Bộ nhớ đệm 30MB, hỗ trợ RAM tối đa 6400MHz và tích hợp đồ họa onboard giúp hệ thống vận hành linh hoạt hơn trong nhiều tình huống sử dụng. Đây là mẫu CPU phù hợp cho các cấu hình hiệu năng cao dùng mainboard nền tảng mới.', N'/uploads/products/cpu/intel-core-ultra-7-265k/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (3, N'CPU-INTEL-CU9-285K', N'Bộ vi xử lý Intel Core Ultra 9 285K', N'bo-vi-xu-ly-intel-core-ultra-9-285k', 1, 1, CAST(17490000.00 AS Decimal(18, 2)), NULL, 108, 0, N'CPU Intel Core Ultra 9 285K, 24 nhân 24 luồng, turbo up to 5.7GHz, socket LGA 1851.', N'Intel Core Ultra 9 285K là bộ xử lý cao cấp dành cho workstation, gaming flagship và các hệ thống yêu cầu hiệu năng cực cao. CPU có 24 nhân 24 luồng, trong đó gồm 8 P-core và 16 E-core, kết hợp bộ nhớ đệm 36MB và xung nhịp tối đa lên đến 5.7GHz. Sản phẩm hỗ trợ RAM tốc độ cao 6400MHz, có đồ họa tích hợp và mang lại hiệu quả mạnh mẽ trong render, xử lý video, lập trình nặng và các tác vụ sáng tạo chuyên sâu.', N'/uploads/products/cpu/intel-core-ultra-9-285k/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (4, N'CPU-INTEL-I3-14100', N'Bộ vi xử lý Intel Core i3 14100', N'bo-vi-xu-ly-intel-core-i3-14100', 1, 1, CAST(4400000.00 AS Decimal(18, 2)), CAST(3890000.00 AS Decimal(18, 2)), 125, 0, N'CPU Intel Core i3 14100, 4 nhân 8 luồng, turbo up to 4.7GHz, socket LGA 1700.', N'Intel Core i3 14100 là lựa chọn phù hợp cho máy tính văn phòng, học tập, giải trí phổ thông và gaming eSports nhẹ. CPU có 4 nhân 8 luồng, xung tối đa 4.7GHz, bộ nhớ đệm 12MB và tích hợp đồ họa onboard giúp tiết kiệm chi phí khi chưa cần card đồ họa rời. Sản phẩm dùng socket LGA 1700, hỗ trợ RAM tối đa 4800MHz và thích hợp cho các cấu hình phổ thông có mức giá dễ tiếp cận.', N'/uploads/products/cpu/intel-core-i3-14100/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (5, N'CPU-AMD-R3-4300G', N'Bộ vi xử lý AMD Ryzen 3 4300G', N'bo-vi-xu-ly-amd-ryzen-3-4300g', 1, 2, CAST(2790000.00 AS Decimal(18, 2)), CAST(2490000.00 AS Decimal(18, 2)), 120, 0, N'CPU AMD Ryzen 3 4300G, 4 nhân 8 luồng, boost up to 4.0GHz, socket AM4.', N'AMD Ryzen 3 4300G là bộ xử lý phổ thông tích hợp đồ họa, rất phù hợp cho nhu cầu học tập, làm việc văn phòng và giải trí cơ bản mà không cần card đồ họa rời. CPU có 4 nhân 8 luồng, xung boost 4.0GHz, bộ nhớ đệm 6MB và hỗ trợ RAM tối đa 3200MHz. Với socket AM4 phổ biến và mức giá dễ tiếp cận, đây là lựa chọn tốt để xây dựng cấu hình tiết kiệm nhưng vẫn đảm bảo hiệu năng ổn định.', N'/uploads/products/cpu/amd-ryzen-3-4300g/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (6, N'CPU-AMD-R5-7600', N'Bộ vi xử lý AMD Ryzen 5 7600', N'bo-vi-xu-ly-amd-ryzen-5-7600', 1, 2, CAST(5990000.00 AS Decimal(18, 2)), CAST(5790000.00 AS Decimal(18, 2)), 122, 0, N'CPU AMD Ryzen 5 7600, 6 nhân 12 luồng, boost up to 5.1GHz, socket AM5.', N'AMD Ryzen 5 7600 là một trong những CPU tầm trung rất đáng chú ý cho gaming và làm việc hằng ngày. Sản phẩm có 6 nhân 12 luồng, xung boost tối đa 5.1GHz, bộ nhớ đệm 38MB và tích hợp đồ họa onboard, phù hợp cho cả người dùng mới build máy lẫn người cần hiệu năng ổn định lâu dài. CPU sử dụng socket AM5 và hỗ trợ RAM DDR5, mang lại khả năng nâng cấp tốt cho các cấu hình thế hệ mới.', N'/uploads/products/cpu/amd-ryzen-5-7600/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (7, N'CPU-AMD-R7-9700X', N'Bộ vi xử lý AMD Ryzen 7 9700X', N'bo-vi-xu-ly-amd-ryzen-7-9700x', 1, 2, CAST(9990000.00 AS Decimal(18, 2)), NULL, 114, 0, N'CPU AMD Ryzen 7 9700X, 8 nhân 16 luồng, boost up to 5.5GHz, socket AM5.', N'AMD Ryzen 7 9700X hướng đến game thủ cao cấp và người dùng sáng tạo nội dung cần hiệu năng mạnh trong phân khúc cận cao cấp. CPU có 8 nhân 16 luồng, xung boost lên đến 5.5GHz, bộ nhớ đệm 40MB và hỗ trợ RAM tốc độ cao 5600MHz. Sản phẩm dùng socket AM5, phù hợp cho các bộ máy gaming mạnh, làm việc đa nhiệm nặng và xử lý tác vụ render ở mức cao.', N'/uploads/products/cpu/amd-ryzen-7-9700x/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (8, N'CPU-AMD-R9-9950X', N'Bộ vi xử lý AMD Ryzen 9 9950X', N'bo-vi-xu-ly-amd-ryzen-9-9950x', 1, 2, CAST(17590000.00 AS Decimal(18, 2)), NULL, 0, 16, N'CPU AMD Ryzen 9 9950X, 16 nhân 32 luồng, boost up to 5.7GHz, socket AM5.', N'AMD Ryzen 9 9950X là bộ vi xử lý cao cấp dành cho workstation, render, dựng phim, lập trình nặng và hệ thống gaming flagship. CPU có 16 nhân 32 luồng, bộ nhớ đệm 80MB, xung boost tối đa 5.7GHz và hỗ trợ RAM tối đa 5200MHz. Đây là lựa chọn phù hợp cho người dùng cần sức mạnh xử lý đa luồng rất cao, hiệu suất ổn định và nền tảng AM5 mới để đầu tư lâu dài.', N'/uploads/products/cpu/amd-ryzen-9-9950x/thumb.jpg', 36, 1, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), CAST(N'2026-04-09T23:11:57.4733110' AS DateTime2))
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (9, N'CPU-AMD-ATHLON-3000G', N'Bộ vi xử lý AMD Athlon 3000G', N'bo-vi-xu-ly-amd-athlon-3000g', 1, 2, CAST(1990000.00 AS Decimal(18, 2)), CAST(1290000.00 AS Decimal(18, 2)), 115, 1, N'CPU AMD Athlon 3000G, 2 nhân 4 luồng, 3.5GHz, socket AM4.', N'AMD Athlon 3000G là CPU giá rẻ dành cho máy tính văn phòng cơ bản, máy học tập hoặc cấu hình tối ưu chi phí. Sản phẩm có 2 nhân 4 luồng, xung nhịp 3.5GHz, bộ nhớ đệm 5MB và tích hợp đồ họa onboard, đủ dùng cho các tác vụ nhẹ như duyệt web, văn bản, học online và quản lý bán hàng. Với socket AM4 thông dụng, đây là lựa chọn hợp lý cho các hệ thống tiết kiệm.', N'/uploads/products/cpu/amd-athlon-3000g/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (10, N'CPU-AMD-R9-9950X-TRAY', N'Bộ vi xử lý AMD Ryzen 9 9950X TRAY', N'bo-vi-xu-ly-amd-ryzen-9-9950x-tray', 1, 2, CAST(17490000.00 AS Decimal(18, 2)), CAST(16990000.00 AS Decimal(18, 2)), 103, 2, N'CPU AMD Ryzen 9 9950X TRAY, 16 nhân 32 luồng, boost up to 5.7GHz, socket AM5.', N'AMD Ryzen 9 9950X TRAY là phiên bản không hộp của dòng Ryzen 9 cao cấp, phù hợp cho người dùng chuyên nghiệp, cửa hàng build PC hoặc hệ thống workstation cần tối ưu chi phí đầu vào. CPU vẫn sở hữu 16 nhân 32 luồng, bộ nhớ đệm 80MB và xung boost tối đa 5.7GHz, đem lại hiệu năng rất mạnh trong các tác vụ nặng như render, biên dịch mã nguồn và xử lý video. Do là phiên bản TRAY, sản phẩm thường phù hợp với người dùng đã có sẵn giải pháp tản nhiệt và cần lưu ý thời hạn bảo hành ngắn hơn bản BOX.', N'/uploads/products/cpu/amd-ryzen-9-9950x-tray/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (12, N'CMK8GX4M1E3200C16', N'RAM Corsair Vengeance LPX 8GB (1x8GB) 3200 DDR4 Black (CMK8GX4M1E3200C16)', N'ram-corsair-vengeance-lpx-8gb-1x8gb-3200-ddr4-black-cmk8gx4m1e3200c16', 2, 3, CAST(1990000.00 AS Decimal(18, 2)), CAST(1690000.00 AS Decimal(18, 2)), 118, 6, N'RAM Corsair Vengeance LPX 8GB DDR4 bus 3200, thiết kế low-profile, phù hợp PC gaming và văn phòng.', N'Corsair Vengeance LPX 8GB DDR4 3200 là dòng RAM phổ thông chất lượng cao dành cho máy tính để bàn, phù hợp cho cấu hình học tập, văn phòng, gaming eSports và nâng cấp hệ thống giá tốt. Sản phẩm có dung lượng 8GB, bus 3200MHz, hỗ trợ Intel XMP, tản nhiệt nhôm và thiết kế low-profile dễ tương thích với nhiều bộ tản CPU.', N'/uploads/products/ram/corsair-vengeance-lpx-8gb-3200-cmk8gx4m1e3200c16/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (13, N'KF432C16BBA/8', N'RAM Kingston Fury Beast 8GB 3200 DDR4 RGB Black (KF432C16BBA/8)', N'ram-kingston-fury-beast-8gb-3200-ddr4-rgb-black-kf432c16bba-8', 2, 4, CAST(1290000.00 AS Decimal(18, 2)), CAST(850000.00 AS Decimal(18, 2)), 100, 0, N'RAM Kingston Fury Beast 8GB DDR4 RGB bus 3200, thiết kế gaming, có LED RGB.', N'Kingston Fury Beast 8GB DDR4 RGB 3200 là lựa chọn phù hợp cho người dùng muốn nâng cấp bộ nhớ với chi phí hợp lý nhưng vẫn có ngoại hình đẹp mắt cho hệ thống gaming. RAM sở hữu bus 3200MHz, LED RGB nổi bật, tản nhiệt tốt và tương thích với nhiều bo mạch chủ phổ biến.', N'/uploads/products/ram/kingston-fury-beast-8gb-3200-kf432c16bba-8/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (14, N'CMP32GX5M2B6000C30', N'RAM Corsair Dominator Titanium Black 32GB (2x16GB) RGB 6000 DDR5 (CMP32GX5M2B6000C30)', N'ram-corsair-dominator-titanium-black-32gb-2x16gb-rgb-6000-ddr5-cmp32gx5m2b6000c30', 2, 3, CAST(11990000.00 AS Decimal(18, 2)), CAST(10990000.00 AS Decimal(18, 2)), 108, 1, N'RAM Corsair Dominator Titanium 32GB DDR5 bus 6000, RGB cao cấp, tối ưu cho PC flagship.', N'Corsair Dominator Titanium Black 32GB DDR5 6000 là dòng RAM cao cấp hướng tới game thủ enthusiast, người làm đồ họa và hệ thống hiệu năng cao. Bộ kit 2x16GB mang lại khả năng đa nhiệm mạnh, hỗ trợ Intel XMP, RGB đẹp mắt, tản nhiệt hiệu quả và kiểu dáng premium cho dàn PC cao cấp.', N'/uploads/products/ram/corsair-dominator-titanium-black-32gb-6000-cmp32gx5m2b6000c30/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (15, N'CMH32GX5M2B5600C40W', N'RAM Corsair Vengeance RGB White 32GB (2x16GB) 5600 DDR5 (CMH32GX5M2B5600C40W)', N'ram-corsair-vengeance-rgb-white-32gb-2x16gb-5600-ddr5-cmh32gx5m2b5600c40w', 2, 3, CAST(5690000.00 AS Decimal(18, 2)), NULL, 113, 0, N'RAM Corsair Vengeance RGB White 32GB DDR5 bus 5600, màu trắng, phù hợp build PC tone sáng.', N'Corsair Vengeance RGB White 32GB DDR5 5600 là bộ nhớ dành cho các hệ thống desktop hiện đại cần dung lượng lớn, ngoại hình đẹp và hiệu năng ổn định. Sản phẩm gồm 2 thanh 16GB, hỗ trợ LED RGB, bus 5600MHz và tản nhiệt tốt, rất phù hợp với các bộ máy gaming hoặc workstation tone trắng.', N'/uploads/products/ram/corsair-vengeance-rgb-white-32gb-5600-cmh32gx5m2b5600c40w/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (16, N'CMP64GX5M2B6000C30W', N'RAM Corsair Dominator Titanium White 64GB (2x32GB) RGB 6000 DDR5 (CMP64GX5M2B6000C30W)', N'ram-corsair-dominator-titanium-white-64gb-2x32gb-rgb-6000-ddr5-cmp64gx5m2b6000c30w', 2, 3, CAST(31990000.00 AS Decimal(18, 2)), CAST(21490000.00 AS Decimal(18, 2)), 102, 2, N'RAM Corsair Dominator Titanium White 64GB DDR5 6000, RGB cao cấp, dung lượng lớn cho workstation.', N'Corsair Dominator Titanium White 64GB DDR5 6000 là bộ nhớ cao cấp dành cho hệ thống làm việc chuyên sâu, dựng phim, render, AI workstation và gaming flagship. Bộ kit 2x32GB mang lại dung lượng rất lớn, hỗ trợ Intel XMP, LED RGB đẹp mắt, tản nhiệt tốt và màu trắng cao cấp phù hợp với các bộ máy thẩm mỹ cao.', N'/uploads/products/ram/corsair-dominator-titanium-white-64gb-6000-cmp64gx5m2b6000c30w/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (17, N'RAM-TEAMGROUP-TFORCE-DELTA-16G-3600-BLACK', N'RAM TeamGroup T-Force Delta RGB Black 16GB (1x16GB) 3600 DDR4', N'ram-teamgroup-t-force-delta-rgb-black-16gb-1x16gb-3600-ddr4', 2, 5, CAST(3990000.00 AS Decimal(18, 2)), CAST(3490000.00 AS Decimal(18, 2)), 116, 1, N'RAM TeamGroup T-Force Delta RGB 16GB DDR4 bus 3600, LED RGB, phù hợp gaming.', N'TeamGroup T-Force Delta RGB Black 16GB DDR4 3600 là thanh RAM hiệu năng tốt trong phân khúc gaming tầm trung, thích hợp cho cấu hình chơi game, stream và làm việc đa nhiệm. Sản phẩm có bus 3600MHz, 1 thanh 16GB, hỗ trợ Intel XMP, LED RGB nổi bật và thiết kế tản nhiệt đậm chất gaming.', N'/uploads/products/ram/teamgroup-tforce-delta-black-16gb-3600/thumb.jpg', 60, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (18, N'F5-5600J4040C16GX2-TZ5RS', N'RAM G.Skill Trident Z5 RGB 32GB (2x16GB) 5600 DDR5 Silver CL40 (F5-5600J4040C16GX2-TZ5RS)', N'ram-g-skill-trident-z5-rgb-32gb-2x16gb-5600-ddr5-silver-cl40-f5-5600j4040c16gx2-tz5rs', 2, 6, CAST(10990000.00 AS Decimal(18, 2)), CAST(9990000.00 AS Decimal(18, 2)), 110, 0, N'RAM G.Skill Trident Z5 RGB 32GB DDR5 bus 5600, màu silver, thiết kế cao cấp.', N'G.Skill Trident Z5 RGB 32GB DDR5 5600 Silver CL40 là bộ nhớ cao cấp cho desktop hiện đại, phù hợp cho gaming, làm việc sáng tạo nội dung và các cấu hình yêu cầu tính thẩm mỹ cao. Bộ kit 2x16GB hỗ trợ Intel XMP, AMD EXPO, LED RGB và thiết kế tản nhiệt kim loại sang trọng.', N'/uploads/products/ram/gskill-trident-z5-rgb-32gb-5600-f5-5600j4040c16gx2-tz5rs/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (19, N'F5-6000J3040G32GX2-TZ5RS', N'RAM G.Skill Trident Z5 RGB 64GB (2x32GB) 6000 DDR5 Silver (F5-6000J3040G32GX2-TZ5RS)', N'ram-g-skill-trident-z5-rgb-64gb-2x32gb-6000-ddr5-silver-f5-6000j3040g32gx2-tz5rs', 2, 6, CAST(10990000.00 AS Decimal(18, 2)), CAST(6990000.00 AS Decimal(18, 2)), 100, 0, N'RAM G.Skill Trident Z5 RGB 64GB DDR5 bus 6000, dung lượng lớn, phù hợp workstation.', N'G.Skill Trident Z5 RGB 64GB DDR5 6000 Silver là bộ RAM dung lượng lớn dành cho hệ thống workstation, content creation và PC cao cấp cần khả năng đa nhiệm mạnh. Bộ kit 2x32GB hỗ trợ Intel XMP, LED RGB, thiết kế đẹp mắt và bus 6000MHz giúp tối ưu hiệu năng cho nền tảng desktop mới.', N'/uploads/products/ram/gskill-trident-z5-rgb-64gb-6000-f5-6000j3040g32gx2-tz5rs/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (20, N'CMH96GX5M2B5600C40', N'RAM Corsair Vengeance RGB 96GB (2x48GB) 5600 DDR5 Black (CMH96GX5M2B5600C40)', N'ram-corsair-vengeance-rgb-96gb-2x48gb-5600-ddr5-black-cmh96gx5m2b5600c40', 2, 3, CAST(36990000.00 AS Decimal(18, 2)), CAST(33990000.00 AS Decimal(18, 2)), 103, 0, N'RAM Corsair Vengeance RGB 96GB DDR5 bus 5600, dung lượng cực lớn cho workstation và AI PC.', N'Corsair Vengeance RGB 96GB DDR5 5600 Black là giải pháp bộ nhớ dung lượng rất lớn dành cho các máy trạm cao cấp, hệ thống dựng phim, lập trình nặng, ảo hóa và AI workstation. Bộ kit 2x48GB cung cấp không gian RAM rộng rãi, LED RGB hiện đại, tản nhiệt tốt và hiệu năng ổn định trên nền tảng DDR5 mới.', N'/uploads/products/ram/corsair-vengeance-rgb-96gb-5600-cmh96gx5m2b5600c40/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (21, N'CMP96GX5M2B6600C32', N'RAM Corsair Dominator Titanium Black 96GB (2x48GB) RGB 6600 DDR5 (CMP96GX5M2B6600C32)', N'ram-corsair-dominator-titanium-black-96gb-2x48gb-rgb-6600-ddr5-cmp96gx5m2b6600c32', 2, 3, CAST(39990000.00 AS Decimal(18, 2)), CAST(38990000.00 AS Decimal(18, 2)), 101, 1, N'RAM Corsair Dominator Titanium Black 96GB DDR5 bus 6600, RGB cao cấp cho hệ thống flagship.', N'Corsair Dominator Titanium Black 96GB DDR5 6600 là bộ RAM cực cao cấp dành cho những cấu hình flagship cần dung lượng lớn và bus rất cao. Bộ kit 2x48GB thích hợp cho workstation, sáng tạo nội dung chuyên sâu và hệ thống gaming cao cấp, đồng thời mang lại ngoại hình sang trọng, LED RGB đẹp mắt và khả năng tản nhiệt hiệu quả.', N'/uploads/products/ram/corsair-dominator-titanium-black-96gb-6600-cmp96gx5m2b6600c32/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (22, N'GPU-ASUS-ROGMATRIX-RTX4090-24G', N'ASUS ROG Matrix GeForce RTX 4090 24GB GDDR6X', N'asus-rog-matrix-geforce-rtx-4090-24gb-gddr6x', 3, 7, CAST(82990000.00 AS Decimal(18, 2)), CAST(79990000.00 AS Decimal(18, 2)), 99, 3, N'Card đồ họa cao cấp RTX 4090 24GB GDDR6X, tản nhiệt lai radiator, phù hợp PC flagship và workstation.', N'ASUS ROG Matrix GeForce RTX 4090 24GB GDDR6X là mẫu card đồ họa cực cao cấp dành cho hệ thống gaming flagship, AI PC và workstation hiệu năng lớn. Sản phẩm sử dụng GPU NVIDIA GeForce RTX 4090, 24GB GDDR6X, 16384 nhân CUDA và thiết kế tản nhiệt lai với radiator rời. Đây là lựa chọn dành cho người dùng cần hiệu năng đồ họa tối đa, làm việc dựng hình, render và chơi game 4K/8K ở thiết lập rất cao.', N'/uploads/products/gpu/asus-rog-matrix-rtx4090-24g/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (23, N'GPU-ASUS-RTX4070SUPER-12G', N'ASUS GeForce RTX 4070 SUPER 12GB GDDR6X', N'asus-geforce-rtx-4070-super-12gb-gddr6x', 3, 7, CAST(19990000.00 AS Decimal(18, 2)), CAST(18990000.00 AS Decimal(18, 2)), 120, 0, N'Card đồ họa RTX 4070 SUPER 12GB GDDR6X, phù hợp gaming 2K/4K và làm việc sáng tạo nội dung.', N'ASUS GeForce RTX 4070 SUPER 12GB GDDR6X là card đồ họa mạnh trong phân khúc cận cao cấp, phù hợp cho game thủ chơi 2K, 4K và người dùng làm việc với đồ họa, video hay livestream. Sản phẩm có 7168 nhân CUDA, bộ nhớ 12GB GDDR6X, bus 192-bit và hỗ trợ xuất hình đa màn hình với HDMI 2.1 và DisplayPort 1.4a.', N'/uploads/products/gpu/asus-rtx4070-super-12g/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), CAST(N'2026-04-09T23:06:50.4457820' AS DateTime2))
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (24, N'GPU-ASUS-TUF-RTX5070TI-16G', N'ASUS TUF Gaming GeForce RTX 5070 Ti 16GB GDDR7', N'asus-tuf-gaming-geforce-rtx-5070-ti-16gb-gddr7', 3, 7, CAST(33990000.00 AS Decimal(18, 2)), CAST(32990000.00 AS Decimal(18, 2)), 106, 0, N'Card đồ họa RTX 5070 Ti 16GB GDDR7, PCIe 5.0, phù hợp gaming cao cấp và làm việc AI.', N'ASUS TUF Gaming GeForce RTX 5070 Ti 16GB GDDR7 là card đồ họa thế hệ mới hướng đến game thủ cao cấp và người dùng sáng tạo nội dung hiện đại. Card sở hữu 8960 nhân CUDA, bộ nhớ 16GB GDDR7, chuẩn PCI Express 5.0 và hệ thống tản nhiệt TUF bền bỉ. Đây là lựa chọn phù hợp cho cấu hình chơi game AAA, xử lý AI cục bộ và làm việc đồ họa nặng.', N'/uploads/products/gpu/asus-tuf-rtx5070ti-16g/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (25, N'GPU-ASUS-ROG-RTX5080-16G', N'ASUS ROG GeForce RTX 5080 16GB GDDR7', N'asus-rog-geforce-rtx-5080-16gb-gddr7', 3, 7, CAST(46990000.00 AS Decimal(18, 2)), CAST(45990000.00 AS Decimal(18, 2)), 103, 1, N'Card đồ họa RTX 5080 16GB GDDR7, hiệu năng cao cho gaming 4K và workstation hiện đại.', N'ASUS ROG GeForce RTX 5080 16GB GDDR7 là card đồ họa cao cấp dành cho hệ thống gaming 4K, sáng tạo nội dung và build PC flagship. Sản phẩm có 10752 nhân CUDA, bộ nhớ 16GB GDDR7, bus 256-bit, hỗ trợ PCI Express 5.0 và hệ sinh thái ROG cao cấp. Card phù hợp cho người dùng muốn hiệu năng mạnh, ngoại hình đẹp và khả năng tản nhiệt tốt.', N'/uploads/products/gpu/asus-rog-rtx5080-16g/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (26, N'GPU-ASUS-TUF-RTX5090-32G', N'ASUS TUF Gaming GeForce RTX 5090 32GB GDDR7', N'asus-tuf-gaming-geforce-rtx-5090-32gb-gddr7', 3, 7, CAST(86990000.00 AS Decimal(18, 2)), CAST(84990000.00 AS Decimal(18, 2)), 101, 0, N'Card đồ họa RTX 5090 32GB GDDR7, hiệu năng đầu bảng cho AI, render và gaming flagship.', N'ASUS TUF Gaming GeForce RTX 5090 32GB GDDR7 là card đồ họa đầu bảng dành cho người dùng cần sức mạnh xử lý cực cao. Sản phẩm trang bị 21760 nhân CUDA, bộ nhớ 32GB GDDR7, bus 512-bit, hỗ trợ PCI Express 5.0 và xuất hình đa màn hình với HDMI 2.1b cùng DisplayPort 1.4a. Đây là lựa chọn rất mạnh cho AI workstation, dựng phim, mô phỏng và gaming 4K/8K.', N'/uploads/products/gpu/asus-tuf-rtx5090-32g/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (27, N'MB-ASUS-ROG-Z890-HERO', N'Bo mạch chủ ASUS ROG MAXIMUS Z890 HERO (DDR5)', N'bo-mach-chu-asus-rog-maximus-z890-hero-ddr5', 4, 7, CAST(22890000.00 AS Decimal(18, 2)), CAST(19990000.00 AS Decimal(18, 2)), 105, 0, N'Mainboard cao cấp ASUS ROG MAXIMUS Z890 HERO, DDR5, Wi-Fi 7, LAN kép, phù hợp PC flagship.', N'ASUS ROG MAXIMUS Z890 HERO là bo mạch chủ cao cấp dành cho người dùng enthusiast, game thủ hardcore và hệ thống PC hiệu năng cao. Sản phẩm hỗ trợ nền tảng Z890, RAM DDR5, Wi-Fi 7, LAN tốc độ cao 2.5Gbps và 5Gbps, cùng thiết kế VRM mạnh mẽ 22+1+2+2 pha để phục vụ ép xung và vận hành bền bỉ.', N'/uploads/products/mainboard/asus-rog-maximus-z890-hero/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (28, N'MB-ASUS-PROART-Z890-CREATOR-WIFI', N'Bo mạch chủ ASUS ProArt Z890-CREATOR WIFI (DDR5)', N'bo-mach-chu-asus-proart-z890-creator-wifi-ddr5', 4, 7, CAST(16590000.00 AS Decimal(18, 2)), CAST(14990000.00 AS Decimal(18, 2)), 106, 0, N'Mainboard ASUS ProArt Z890-CREATOR WIFI, DDR5, Wi-Fi 7, LAN 10Gbps, tối ưu cho creator workstation.', N'ASUS ProArt Z890-CREATOR WIFI là bo mạch chủ hướng tới người dùng sáng tạo nội dung, thiết kế đồ họa, dựng phim và workstation hiện đại. Bo mạch hỗ trợ RAM DDR5, Wi-Fi 7, LAN kép 10Gbps và 2.5Gbps, VRM 16+1+2+2 pha và hệ thống kết nối xuất hình linh hoạt gồm HDMI, USB-C DP Alt Mode và DisplayPort.', N'/uploads/products/mainboard/asus-proart-z890-creator-wifi/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (29, N'MB-ASUS-ROG-Z890-APEX', N'Bo mạch chủ ASUS ROG MAXIMUS Z890 APEX (DDR5)', N'bo-mach-chu-asus-rog-maximus-z890-apex-ddr5', 4, 7, CAST(22690000.00 AS Decimal(18, 2)), CAST(20290000.00 AS Decimal(18, 2)), 104, 0, N'Mainboard ASUS ROG MAXIMUS Z890 APEX, DDR5, Wi-Fi 7, VRM mạnh, tối ưu ép xung.', N'ASUS ROG MAXIMUS Z890 APEX là bo mạch chủ cao cấp dành cho ép xung và build PC hiệu năng rất cao. Sản phẩm sở hữu VRM 22+1+2+2 pha, Wi-Fi 7, LAN 5Gbps, cổng USB phong phú và hỗ trợ xuất hình qua USB-C DP Alt Mode. Đây là dòng bo mạch phù hợp cho người dùng đam mê hiệu năng và hệ thống gaming cao cấp.', N'/uploads/products/mainboard/asus-rog-maximus-z890-apex/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (30, N'MB-GIGABYTE-Z890-AORUS-ELITE-WIFI7', N'Bo mạch chủ GIGABYTE Z890 AORUS ELITE WIFI7 (DDR5)', N'bo-mach-chu-gigabyte-z890-aorus-elite-wifi7-ddr5', 4, 8, CAST(9990000.00 AS Decimal(18, 2)), CAST(9590000.00 AS Decimal(18, 2)), 111, 0, N'Mainboard GIGABYTE Z890 AORUS ELITE WIFI7, DDR5, Wi-Fi 7, LAN 2.5Gbps, phù hợp gaming cao cấp.', N'GIGABYTE Z890 AORUS ELITE WIFI7 là bo mạch chủ tầm cao dành cho người dùng gaming và nâng cấp PC thế hệ mới. Bo mạch hỗ trợ RAM DDR5, Wi-Fi 7, LAN 2.5Gbps, VRM 16+1+2 pha và hệ thống cổng kết nối phong phú với DisplayPort và Thunderbolt. Đây là lựa chọn tốt cho cấu hình Intel hiện đại cần độ ổn định và khả năng mở rộng cao.', N'/uploads/products/mainboard/gigabyte-z890-aorus-elite-wifi7/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (31, N'MB-GIGABYTE-Z890-EAGLE-WIFI7', N'Bo mạch chủ GIGABYTE Z890 EAGLE WIFI7 (DDR5)', N'bo-mach-chu-gigabyte-z890-eagle-wifi7-ddr5', 4, 8, CAST(7990000.00 AS Decimal(18, 2)), CAST(6990000.00 AS Decimal(18, 2)), 114, 0, N'Mainboard GIGABYTE Z890 EAGLE WIFI7, DDR5, Wi-Fi 7, LAN 2.5Gbps, phù hợp gaming và làm việc.', N'GIGABYTE Z890 EAGLE WIFI7 là bo mạch chủ dành cho người dùng muốn tiếp cận nền tảng Z890 với chi phí hợp lý hơn nhưng vẫn có Wi-Fi 7 và hỗ trợ DDR5. Sản phẩm có VRM 14+1+2 pha, LAN 2.5Gbps, 10 cổng USB và các cổng xuất hình USB-C DP Alt Mode cùng DisplayPort, phù hợp cho cấu hình gaming và làm việc thế hệ mới.', N'/uploads/products/mainboard/gigabyte-z890-eagle-wifi7/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (32, N'MB-ASUS-ROG-Z890-EXTREME', N'Bo mạch chủ ASUS ROG MAXIMUS Z890 EXTREME (DDR5)', N'bo-mach-chu-asus-rog-maximus-z890-extreme-ddr5', 4, 7, CAST(32690000.00 AS Decimal(18, 2)), CAST(28990000.00 AS Decimal(18, 2)), 101, 1, N'Mainboard flagship ASUS ROG MAXIMUS Z890 EXTREME, DDR5, Wi-Fi 7, LAN kép, VRM cực mạnh.', N'ASUS ROG MAXIMUS Z890 EXTREME là bo mạch chủ flagship dành cho người dùng cao cấp nhất, phù hợp cho ép xung nặng, workstation đầu bảng và hệ thống gaming flagship. Bo mạch có VRM 24+1+2+2 pha, LAN 10Gbps và 2.5Gbps, Wi-Fi 7, hỗ trợ xuất hình HDMI và Thunderbolt, cùng hệ thống thiết kế ROG mạnh mẽ cho nhu cầu build PC không giới hạn.', N'/uploads/products/mainboard/asus-rog-maximus-z890-extreme/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (33, N'MB-GIGABYTE-H610M-H-V3-DDR4', N'Bo mạch chủ GIGABYTE H610M-H V3 (DDR4)', N'bo-mach-chu-gigabyte-h610m-h-v3-ddr4', 4, 8, CAST(1990000.00 AS Decimal(18, 2)), CAST(1890000.00 AS Decimal(18, 2)), 120, 0, N'Mainboard phổ thông GIGABYTE H610M-H V3 DDR4, phù hợp PC văn phòng và học tập.', N'GIGABYTE H610M-H V3 DDR4 là bo mạch chủ phổ thông dành cho cấu hình giá rẻ, máy văn phòng, học tập và sử dụng hằng ngày. Sản phẩm hỗ trợ RAM DDR4, LAN 1Gbps, 6 cổng USB, cổng xuất hình VGA và HDMI, cùng thiết kế nhỏ gọn dễ lắp đặt cho các hệ thống tiết kiệm chi phí.', N'/uploads/products/mainboard/gigabyte-h610m-h-v3-ddr4/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (34, N'SSD-SAMSUNG-9100PRO-1TB', N'Ổ cứng SSD Samsung 9100 PRO NVMe M.2 1TB Gen5', N'o-cung-ssd-samsung-9100-pro-nvme-m-2-1tb-gen5', 5, 9, CAST(7490000.00 AS Decimal(18, 2)), CAST(6990000.00 AS Decimal(18, 2)), 106, 1, N'SSD Samsung 9100 PRO 1TB chuẩn NVMe M.2 PCIe Gen5, tốc độ đọc ghi rất cao cho hệ thống cao cấp.', N'Samsung 9100 PRO 1TB Gen5 là mẫu SSD hiệu năng cao dành cho gaming, workstation và các bộ máy cần băng thông lưu trữ cực lớn. Sản phẩm dùng chuẩn M.2 NVMe PCIe Gen5, tốc độ đọc ghi nổi bật, phù hợp cài hệ điều hành, game AAA và các dự án dựng phim nặng.', N'/uploads/products/storage/samsung-9100-pro-1tb/thumb.jpg', 60, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (35, N'SSD-SAMSUNG-990PRO-2TB', N'Ổ cứng SSD Samsung 990 PRO 2TB M.2 PCIe Gen4 NVMe', N'o-cung-ssd-samsung-990-pro-2tb-m-2-pcie-gen4-nvme', 5, 9, CAST(7590000.00 AS Decimal(18, 2)), CAST(6490000.00 AS Decimal(18, 2)), 108, 1, N'SSD Samsung 990 PRO 2TB PCIe Gen4, hiệu năng cao, phù hợp gaming và làm việc chuyên sâu.', N'Samsung 990 PRO 2TB là dòng SSD NVMe Gen4 cao cấp, nổi bật với tốc độ truy xuất nhanh, độ ổn định tốt và độ bền cao. Sản phẩm thích hợp cho máy tính chơi game, máy làm việc đồ họa và các hệ thống cần không gian lưu trữ lớn.', N'/uploads/products/storage/samsung-990-pro-2tb/thumb.jpg', 60, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (36, N'SSD-KINGSTON-NV3-500GB', N'Ổ cứng SSD Kingston NV3 500GB M.2 PCIe NVMe Gen4', N'o-cung-ssd-kingston-nv3-500gb-m-2-pcie-nvme-gen4', 5, 4, CAST(5490000.00 AS Decimal(18, 2)), CAST(3890000.00 AS Decimal(18, 2)), 115, 0, N'SSD Kingston NV3 500GB M.2 PCIe Gen4, lựa chọn lưu trữ phổ thông cho máy tính học tập và văn phòng.', N'Kingston NV3 500GB là giải pháp SSD Gen4 tầm phổ thông với thiết kế M.2 gọn gàng, tốc độ tốt và mức giá dễ tiếp cận. Sản phẩm phù hợp nâng cấp laptop và PC văn phòng, giúp cải thiện tốc độ khởi động máy và mở ứng dụng.', N'/uploads/products/storage/kingston-nv3-500gb/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (37, N'SSD-KINGSTON-NV3-1TB', N'Ổ cứng SSD Kingston NV3 1TB M.2 PCIe NVMe Gen4', N'o-cung-ssd-kingston-nv3-1tb-m-2-pcie-nvme-gen4', 5, 4, CAST(5990000.00 AS Decimal(18, 2)), CAST(5790000.00 AS Decimal(18, 2)), 113, 0, N'SSD Kingston NV3 1TB chuẩn M.2 PCIe Gen4, dung lượng tốt cho nhu cầu học tập, làm việc và gaming.', N'Kingston NV3 1TB Gen4 mang lại dung lượng đủ dùng cho hệ điều hành, game, ứng dụng và dữ liệu cá nhân. Đây là lựa chọn hợp lý cho người dùng cần SSD nhanh, ổn định và dễ lắp đặt trong nhiều cấu hình PC/laptop.', N'/uploads/products/storage/kingston-nv3-1tb/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (38, N'SSD-KINGSTON-NV3-2TB', N'Ổ cứng SSD Kingston NV3 2TB M.2 PCIe NVMe Gen4', N'o-cung-ssd-kingston-nv3-2tb-m-2-pcie-nvme-gen4', 5, 4, CAST(11490000.00 AS Decimal(18, 2)), CAST(10990000.00 AS Decimal(18, 2)), 108, 0, N'SSD Kingston NV3 2TB Gen4, dung lượng lớn cho lưu trữ game, dữ liệu và công việc chuyên môn.', N'Kingston NV3 2TB là SSD M.2 NVMe Gen4 có dung lượng lớn, đáp ứng tốt nhu cầu lưu trữ dài hạn cho game thủ, người dựng video, lập trình viên hoặc người dùng văn phòng cần nhiều không gian dữ liệu.', N'/uploads/products/storage/kingston-nv3-2tb/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (39, N'HDD-SEAGATE-BARRACUDA-2TB', N'Ổ cứng HDD Seagate Barracuda 2TB', N'o-cung-hdd-seagate-barracuda-2tb', 5, 16, CAST(3490000.00 AS Decimal(18, 2)), CAST(3290000.00 AS Decimal(18, 2)), 101, 15, N'HDD Seagate Barracuda 2TB 3.5 inch cho lưu trữ dữ liệu, backup và máy tính văn phòng.', N'Seagate Barracuda 2TB là dòng ổ cứng HDD phổ biến cho nhu cầu lưu trữ dữ liệu, phim ảnh, game nhẹ và sao lưu. Sản phẩm phù hợp cho desktop cần mở rộng dung lượng với chi phí hợp lý.', N'/uploads/products/storage/seagate-barracuda-2tb/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (40, N'HDD-WD-BLUE-6TB', N'Ổ cứng HDD WD Blue 6TB 5400RPM', N'o-cung-hdd-wd-blue-6tb-5400rpm', 5, 17, CAST(4890000.00 AS Decimal(18, 2)), CAST(4490000.00 AS Decimal(18, 2)), 100, 10, N'HDD WD Blue 6TB dung lượng lớn, phù hợp lưu trữ dữ liệu, backup và media server cá nhân.', N'WD Blue 6TB 5400RPM là lựa chọn tốt cho người dùng cần dung lượng lưu trữ lớn với độ ổn định cao. Sản phẩm phù hợp cho máy tính cá nhân, NAS cơ bản hoặc hệ thống lưu trữ phim, ảnh và dữ liệu công việc.', N'/uploads/products/storage/wd-blue-6tb-5400rpm/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (41, N'HDD-WD-BLUE-4TB', N'Ổ cứng HDD WD Blue 4TB', N'o-cung-hdd-wd-blue-4tb', 5, 17, CAST(3890000.00 AS Decimal(18, 2)), CAST(3590000.00 AS Decimal(18, 2)), 112, 0, N'HDD WD Blue 4TB cho desktop, lưu trữ dữ liệu lớn với chi phí hợp lý.', N'WD Blue 4TB mang đến dung lượng lớn cho người dùng desktop cần lưu trữ tài liệu, game, hình ảnh hoặc video. Sản phẩm phù hợp cho cả môi trường văn phòng và sử dụng tại nhà.', N'/uploads/products/storage/wd-blue-4tb/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (42, N'HDD-WD-BLUE-2TB-7200', N'Ổ cứng HDD WD Blue 2TB 7200RPM', N'o-cung-hdd-wd-blue-2tb-7200rpm', 5, 17, CAST(3450000.00 AS Decimal(18, 2)), CAST(3290000.00 AS Decimal(18, 2)), 114, 0, N'HDD WD Blue 2TB 7200RPM cho hiệu năng đọc ghi tốt hơn trong phân khúc HDD phổ thông.', N'WD Blue 2TB 7200RPM là ổ cứng HDD phù hợp cho người dùng cần dung lượng vừa phải nhưng vẫn muốn tốc độ truy xuất khá. Sản phẩm thích hợp cho desktop văn phòng, học tập và lưu trữ dữ liệu cá nhân.', N'/uploads/products/storage/wd-blue-2tb-7200rpm/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (43, N'HDD-WD-BLUE-1TB', N'Ổ cứng HDD WD Blue 1TB', N'o-cung-hdd-wd-blue-1tb', 5, 17, CAST(2990000.00 AS Decimal(18, 2)), CAST(2690000.00 AS Decimal(18, 2)), 118, 0, N'HDD WD Blue 1TB là lựa chọn lưu trữ phổ thông cho desktop học tập, văn phòng và gia đình.', N'WD Blue 1TB phù hợp làm ổ lưu trữ bổ sung cho desktop với mức chi phí thấp, độ ổn định tốt và dung lượng đủ dùng cho tài liệu, phần mềm và dữ liệu cá nhân.', N'/uploads/products/storage/wd-blue-1tb/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (44, N'PSU-ASUS-ROG-THOR-850P', N'Nguồn máy tính ASUS ROG Thor 850P 80 Plus Platinum Full Modular 850W', N'nguon-may-tinh-asus-rog-thor-850p-80-plus-platinum-full-modular-850w', 6, 7, CAST(5990000.00 AS Decimal(18, 2)), NULL, 108, 0, N'PSU ASUS ROG Thor 850P chuẩn 80 Plus Platinum, Full Modular, phù hợp cấu hình gaming cao cấp.', N'ASUS ROG Thor 850P là bộ nguồn cao cấp dành cho các cấu hình gaming và workstation yêu cầu độ ổn định điện năng cao. Sản phẩm có chuẩn Platinum, thiết kế Full Modular, độ hoàn thiện tốt và nhiều tính năng bảo vệ an toàn.', N'/uploads/products/psu/asus-rog-thor-850p/thumb.jpg', 120, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (45, N'PSU-ASUS-ROG-THOR-1200P2', N'Nguồn máy tính ASUS ROG Thor 1200P2 80 Plus Platinum Full Modular 1200W', N'nguon-may-tinh-asus-rog-thor-1200p2-80-plus-platinum-full-modular-1200w', 6, 7, CAST(9990000.00 AS Decimal(18, 2)), CAST(9490000.00 AS Decimal(18, 2)), 103, 2, N'PSU ASUS ROG Thor 1200P2 công suất 1200W, 80 Plus Platinum, phù hợp cấu hình cực mạnh.', N'ASUS ROG Thor 1200P2 là bộ nguồn cao cấp cho hệ thống nhiều VGA, workstation và cấu hình đòi hỏi công suất lớn. Sản phẩm hỗ trợ chuẩn ATX 3.0, Full Modular và độ bền cao cho vận hành lâu dài.', N'/uploads/products/psu/asus-rog-thor-1200p2/thumb.jpg', 120, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (46, N'PSU-ASUS-ROG-STRIX-1000-AURA', N'Nguồn máy tính ASUS ROG Strix 1000W AURA Edition 80 Plus Gold Full Modular', N'nguon-may-tinh-asus-rog-strix-1000w-aura-edition-80-plus-gold-full-modular', 6, 7, CAST(6490000.00 AS Decimal(18, 2)), CAST(5990000.00 AS Decimal(18, 2)), 107, 0, N'PSU ASUS ROG Strix 1000W AURA Edition, 80 Plus Gold, Full Modular cho PC gaming mạnh.', N'ASUS ROG Strix 1000W AURA Edition là bộ nguồn phù hợp cho cấu hình gaming cao cấp, hỗ trợ chuẩn ATX 3.0, thiết kế Full Modular, hiệu suất ổn định và đồng bộ Aura Sync đẹp mắt.', N'/uploads/products/psu/asus-rog-strix-1000w-aura/thumb.jpg', 120, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (47, N'PSU-GIGABYTE-UD850GM-PG5', N'Nguồn máy tính GIGABYTE UD850GM PG5 80 Plus Gold Full Modular 850W', N'nguon-may-tinh-gigabyte-ud850gm-pg5-80-plus-gold-full-modular-850w', 6, 8, CAST(3490000.00 AS Decimal(18, 2)), CAST(2990000.00 AS Decimal(18, 2)), 111, 0, N'PSU GIGABYTE UD850GM PG5 850W, 80 Plus Gold, Full Modular, tương thích cấu hình hiện đại.', N'GIGABYTE UD850GM PG5 là bộ nguồn 850W hướng đến người dùng cần mức công suất tốt, chuẩn Gold, thiết kế Full Modular và hỗ trợ đầu nguồn mới cho VGA hiện đại. Đây là lựa chọn cân bằng giữa giá thành và hiệu năng.', N'/uploads/products/psu/gigabyte-ud850gm-pg5/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (48, N'PSU-ASUS-ROG-THOR-1600T3', N'Nguồn máy tính ASUS ROG Thor 1600T3 ATX 3.1 PCIe 5.0 80 Plus Titanium Full Modular 1600W', N'nguon-may-tinh-asus-rog-thor-1600t3-atx-3-1-pcie-5-0-80-plus-titanium-full-modular-1600w', 6, 7, CAST(24990000.00 AS Decimal(18, 2)), CAST(24490000.00 AS Decimal(18, 2)), 103, 0, N'PSU ASUS ROG Thor 1600T3 chuẩn Titanium cực cao cấp cho cấu hình workstation và enthusiast.', N'ASUS ROG Thor 1600T3 là bộ nguồn đầu bảng cho cấu hình cực mạnh, hỗ trợ ATX 3.1, PCIe 5.0 và chuẩn 80 Plus Titanium. Sản phẩm thích hợp cho hệ thống đa card, AI workstation hoặc PC trình diễn cao cấp.', N'/uploads/products/psu/asus-rog-thor-1600t3/thumb.jpg', 120, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (49, N'CASE-CORSAIR-6500X-WHITE', N'Vỏ máy tính Corsair 6500X TG Mid-Tower White (CC-9011258-WW)', N'vo-may-tinh-corsair-6500x-tg-mid-tower-white-cc-9011258-ww', 7, 3, CAST(4490000.00 AS Decimal(18, 2)), NULL, 108, 1, N'Case Corsair 6500X màu trắng, thiết kế kính cường lực, phù hợp cho dàn PC trưng bày cao cấp.', N'Corsair 6500X TG Mid-Tower White là mẫu case cao cấp với không gian rộng rãi, thiết kế kính cường lực đẹp mắt và khả năng đi dây tốt. Sản phẩm phù hợp cho cấu hình gaming, streaming hoặc build showcase tone trắng.', N'/uploads/products/case/corsair-6500x-white/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (50, N'CASE-JONSBO-Z20-WHITE', N'Vỏ máy tính Jonsbo Z20 White', N'vo-may-tinh-jonsbo-z20-white', 7, 20, CAST(1750000.00 AS Decimal(18, 2)), CAST(1650000.00 AS Decimal(18, 2)), 112, 0, N'Case Jonsbo Z20 White nhỏ gọn, có kính cường lực và hỗ trợ build PC tone trắng đẹp mắt.', N'Jonsbo Z20 White là mẫu case gọn gàng, phù hợp cho các bộ máy mini hoặc micro-ATX hiện đại. Thiết kế màu trắng kết hợp kính cường lực giúp bộ máy nổi bật và thẩm mỹ hơn trên bàn làm việc.', N'/uploads/products/case/jonsbo-z20-white/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (51, N'CASE-JONSBO-Z20-PINK', N'Vỏ máy tính Jonsbo Z20 Pink', N'vo-may-tinh-jonsbo-z20-pink', 7, 20, CAST(1990000.00 AS Decimal(18, 2)), CAST(1890000.00 AS Decimal(18, 2)), 110, 0, N'Case Jonsbo Z20 Pink cá tính, phù hợp build PC tone hồng hoặc góc setup nổi bật.', N'Jonsbo Z20 Pink là lựa chọn cho người dùng thích build máy tính có màu sắc riêng. Sản phẩm có thiết kế gọn, kính cường lực và phù hợp với nhiều cấu hình PC giải trí hoặc gaming nhẹ.', N'/uploads/products/case/jonsbo-z20-pink/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (52, N'CASE-COOLERMASTER-TD500-V2-CHUNLI', N'Vỏ máy tính Cooler Master MASTERBOX TD500 MESH V2 CHUN-LI', N'vo-may-tinh-cooler-master-masterbox-td500-mesh-v2-chun-li', 7, 19, CAST(2790000.00 AS Decimal(18, 2)), CAST(2490000.00 AS Decimal(18, 2)), 108, 0, N'Case Cooler Master TD500 Mesh V2 bản CHUN-LI độc đáo, có sẵn quạt ARGB và mặt lưới thoáng.', N'MASTERBOX TD500 MESH V2 CHUN-LI là mẫu case nổi bật dành cho game thủ thích phong cách khác biệt. Sản phẩm có mặt trước thoáng khí, đi kèm quạt ARGB và không gian phù hợp cho cấu hình gaming tầm trung đến cao cấp.', N'/uploads/products/case/cooler-master-td500-v2-chunli/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (53, N'CASE-NZXT-H9-ELITE-WHITE', N'Vỏ máy tính NZXT H9 Elite White', N'vo-may-tinh-nzxt-h9-elite-white', 7, 18, CAST(6990000.00 AS Decimal(18, 2)), CAST(5290000.00 AS Decimal(18, 2)), 106, 0, N'Case NZXT H9 Elite White cao cấp, thiết kế hai mặt kính đẹp mắt và tối ưu cho build trình diễn.', N'NZXT H9 Elite White hướng đến người dùng yêu thích build PC showcase. Sản phẩm có không gian rộng, hỗ trợ nhiều quạt và radiator, phù hợp cho hệ thống gaming hoặc làm việc cao cấp tone trắng.', N'/uploads/products/case/nzxt-h9-elite-white/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (54, N'CASE-TRYX-LUCA-L70-BLACK', N'Vỏ máy tính TRYX Luca L70 Mid Tower Black', N'vo-may-tinh-tryx-luca-l70-mid-tower-black', 7, 21, CAST(5590000.00 AS Decimal(18, 2)), CAST(5490000.00 AS Decimal(18, 2)), 105, 0, N'Case TRYX Luca L70 Mid Tower màu đen, thiết kế hiện đại và hỗ trợ build PC cao cấp.', N'TRYX Luca L70 Mid Tower Black là mẫu case mạnh về thẩm mỹ và không gian lắp ráp. Sản phẩm phù hợp cho cấu hình gaming cao cấp với khả năng hỗ trợ linh kiện dài, nhiều vị trí quạt và kính cường lực sang trọng.', N'/uploads/products/case/tryx-luca-l70-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (55, N'CASE-JONSBO-D300-BLACK', N'Vỏ máy tính Jonsbo D300 Black', N'vo-may-tinh-jonsbo-d300-black', 7, 20, CAST(1890000.00 AS Decimal(18, 2)), CAST(1790000.00 AS Decimal(18, 2)), 111, 0, N'Case Jonsbo D300 Black thiết kế hiện đại, hỗ trợ kính cường lực và build gọn gàng.', N'Jonsbo D300 Black là lựa chọn phù hợp trong phân khúc dễ tiếp cận cho người dùng thích thiết kế hiện đại, không gian lắp linh hoạt và vẻ ngoài tối giản mạnh mẽ.', N'/uploads/products/case/jonsbo-d300-black/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (56, N'CASE-CORSAIR-6500X-BLACK', N'Vỏ máy tính Corsair 6500X TG Mid-Tower Black (CC-9011257-WW)', N'vo-may-tinh-corsair-6500x-tg-mid-tower-black-cc-9011257-ww', 7, 3, CAST(3990000.00 AS Decimal(18, 2)), NULL, 107, 1, N'Case Corsair 6500X màu đen, kính cường lực, không gian rộng cho build PC cao cấp.', N'Corsair 6500X TG Mid-Tower Black phù hợp với người dùng cần một mẫu case rộng rãi, đi dây đẹp, hỗ trợ tốt cho tản nhiệt nước và dàn linh kiện cao cấp trong tông màu đen sang trọng.', N'/uploads/products/case/corsair-6500x-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (57, N'CASE-ASUS-ROG-HYPERION-GR701', N'Vỏ máy tính ASUS ROG Hyperion GR701', N'vo-may-tinh-asus-rog-hyperion-gr701', 7, 7, CAST(10990000.00 AS Decimal(18, 2)), NULL, 104, 0, N'Case ASUS ROG Hyperion GR701 cỡ lớn, hỗ trợ build enthusiast và hệ thống tản nhiệt khủng.', N'ASUS ROG Hyperion GR701 là mẫu case full tower cao cấp dành cho các cấu hình flagship. Sản phẩm hỗ trợ mainboard cỡ lớn, nhiều quạt, radiator lớn và có thiết kế ROG đậm chất gaming cao cấp.', N'/uploads/products/case/asus-rog-hyperion-gr701/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (58, N'CASE-JONSBO-TK3-WHITE', N'Vỏ máy tính Jonsbo TK3 White', N'vo-may-tinh-jonsbo-tk3-white', 7, 20, CAST(2090000.00 AS Decimal(18, 2)), CAST(1990000.00 AS Decimal(18, 2)), 109, 0, N'Case Jonsbo TK3 White có kính cường lực và LED RGB, phù hợp build PC gaming tone trắng.', N'Jonsbo TK3 White là mẫu case tầm trung có thiết kế hiện đại, hỗ trợ RGB, phù hợp với các cấu hình PC chơi game và làm việc sử dụng mainboard ATX hoặc mATX trong không gian gọn gàng.', N'/uploads/products/case/jonsbo-tk3-white/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (59, N'MON-SAMSUNG-27Q180-IPS', N'Màn hình Samsung 27Q180 IPS Gaming 27 inch 2K 180Hz', N'man-hinh-samsung-27q180-ips-gaming-27-inch-2k-180hz', 8, 9, CAST(5490000.00 AS Decimal(18, 2)), CAST(4990000.00 AS Decimal(18, 2)), 114, 0, N'Màn hình Samsung 27 inch IPS, 2K, 180Hz, phù hợp chơi game và giải trí.', N'Mẫu màn hình Samsung 27Q180 IPS Gaming phù hợp cho game thủ cần tần số quét cao, độ phân giải 2K sắc nét và màu sắc ổn định. Sản phẩm dùng tấm nền IPS, thời gian phản hồi nhanh và hỗ trợ kết nối cơ bản cho nhu cầu gaming hằng ngày.', N'/uploads/products/monitor/samsung-27q180-ips-gaming/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (60, N'MON-MSI-32U-QDOLED', N'Màn hình MSI 32U QD-OLED Gaming 32 inch 4K', N'man-hinh-msi-32u-qd-oled-gaming-32-inch-4k', 8, 10, CAST(32500000.00 AS Decimal(18, 2)), CAST(22990000.00 AS Decimal(18, 2)), 103, 2, N'Màn hình MSI 32 inch QD-OLED 4K cao cấp cho gaming và trải nghiệm hình ảnh đỉnh cao.', N'Mẫu MSI 32U QD-OLED Gaming hướng tới phân khúc cao cấp với tấm nền QD-OLED, độ phân giải 4K và thời gian phản hồi cực thấp. Sản phẩm phù hợp cho game thủ, người làm nội dung và người dùng cần chất lượng hiển thị cao.', N'/uploads/products/monitor/msi-32u-qdoled-gaming/thumb.jpg', 36, 1, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (61, N'HKC-MB27S9U', N'Màn hình HKC MB27S9U 27 inch 4K IPS', N'man-hinh-hkc-mb27s9u-27-inch-4k-ips', 8, 11, CAST(5990000.00 AS Decimal(18, 2)), CAST(4990000.00 AS Decimal(18, 2)), 109, 0, N'Màn hình HKC 27 inch 4K IPS phù hợp làm việc văn phòng, học tập và giải trí đa phương tiện.', N'HKC MB27S9U là màn hình 27 inch độ phân giải 4K sử dụng tấm nền IPS, phù hợp cho người dùng cần không gian hiển thị lớn, hình ảnh sắc nét và mức giá dễ tiếp cận hơn các dòng đồ họa cao cấp.', N'/uploads/products/monitor/hkc-mb27s9u/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (62, N'MON-ACER-27Q-IPS', N'Màn hình Acer 27Q IPS Gaming 27 inch 2K', N'man-hinh-acer-27q-ips-gaming-27-inch-2k', 8, 12, CAST(4990000.00 AS Decimal(18, 2)), CAST(4290000.00 AS Decimal(18, 2)), 111, 0, N'Màn hình Acer 27 inch IPS 2K cho gaming phổ thông với phản hồi nhanh và thiết kế gọn gàng.', N'Mẫu Acer 27Q IPS Gaming phù hợp cho người dùng cần màn hình 2K sắc nét, thời gian phản hồi thấp và màu sắc ổn định để chơi game, làm việc và học tập hằng ngày.', N'/uploads/products/monitor/acer-27q-ips-gaming/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (63, N'MON-AOC-27Q-FASTIPS', N'Màn hình AOC 27Q Fast IPS Gaming 27 inch 2K', N'man-hinh-aoc-27q-fast-ips-gaming-27-inch-2k', 8, 13, CAST(5490000.00 AS Decimal(18, 2)), CAST(4790000.00 AS Decimal(18, 2)), 110, 0, N'Màn hình AOC 27 inch Fast IPS 2K cho gaming với màu sắc rộng và phản hồi nhanh.', N'AOC 27Q Fast IPS Gaming là mẫu màn hình hướng đến game thủ cần độ phân giải 2K, màu sắc rộng, độ sáng tốt và tốc độ phản hồi nhanh. Sản phẩm phù hợp cho game, xem phim và làm việc sáng tạo cơ bản.', N'/uploads/products/monitor/aoc-27q-fastips-gaming/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (64, N'MON-GIGABYTE-32U-OLED', N'Màn hình Gigabyte 32U OLED Gaming 32 inch 4K', N'man-hinh-gigabyte-32u-oled-gaming-32-inch-4k', 8, 8, CAST(21990000.00 AS Decimal(18, 2)), CAST(19990000.00 AS Decimal(18, 2)), 105, 1, N'Màn hình 32 inch OLED 4K dành cho gaming, màu đen sâu và hiển thị cao cấp.', N'Đây là mẫu màn hình 32 inch OLED 4K được tạm gán theo brand Gigabyte để dùng cho seed data. Sản phẩm hướng tới nhu cầu gaming cao cấp với chất lượng hiển thị nổi bật và thiết kế hiện đại.', N'/uploads/products/monitor/gigabyte-32u-oled-gaming/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (65, N'MON-DELL-43U-IPSBLACK', N'Màn hình Dell 43U IPS Black 43 inch 4K', N'man-hinh-dell-43u-ips-black-43-inch-4k', 8, 22, CAST(18990000.00 AS Decimal(18, 2)), CAST(17490000.00 AS Decimal(18, 2)), 104, 0, N'Màn hình 43 inch 4K IPS Black phù hợp đồ họa, văn phòng và làm việc đa cửa sổ.', N'Đây là mẫu màn hình 43 inch 4K IPS Black được tạm gán theo brand Dell để dùng cho seed data. Sản phẩm phù hợp cho nhu cầu đồ họa, văn phòng, quản lý đa cửa sổ và làm việc chuyên nghiệp.', N'/uploads/products/monitor/dell-43u-ips-black-4k/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (66, N'MON-VIEWSONIC-27Q-COLOR-90W', N'Màn hình ViewSonic 27Q Color USB-C 90W 27 inch 2K', N'man-hinh-viewsonic-27q-color-usb-c-90w-27-inch-2k', 8, 14, CAST(8990000.00 AS Decimal(18, 2)), CAST(7990000.00 AS Decimal(18, 2)), 97, 10, N'Màn hình ViewSonic 27 inch 2K có USB-C 90W, phù hợp đồ họa và làm việc chuyên nghiệp.', N'Mẫu ViewSonic 27Q Color USB-C 90W là màn hình phù hợp cho người dùng văn phòng cao cấp, thiết kế và sáng tạo nội dung. Sản phẩm có độ sáng tốt, màu rộng và hỗ trợ USB-C cấp nguồn 90W rất tiện cho laptop.', N'/uploads/products/monitor/viewsonic-27q-color-usbc-90w/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (67, N'MON-ASUS-32U-WOLED-DUAL', N'Màn hình ASUS 32U WOLED Dual Mode 32 inch 4K 240Hz', N'man-hinh-asus-32u-woled-dual-mode-32-inch-4k-240hz', 8, 7, CAST(36990000.00 AS Decimal(18, 2)), CAST(34990000.00 AS Decimal(18, 2)), 102, 1, N'Màn hình ASUS 32 inch WOLED 4K cao cấp, hỗ trợ Dual Mode 4K 240Hz / FHD 480Hz.', N'ASUS 32U WOLED Dual Mode là màn hình gaming cực cao cấp dành cho người dùng cần cả độ phân giải 4K sắc nét lẫn tốc độ cực cao ở chế độ FHD 480Hz. Sản phẩm phù hợp cho game thủ esports lẫn AAA cao cấp.', N'/uploads/products/monitor/asus-32u-woled-dual-mode/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (68, N'MON-LG-27U-NANOIPS-DUAL', N'Màn hình LG 27U Nano IPS Dual Mode 27 inch 4K 240Hz', N'man-hinh-lg-27u-nano-ips-dual-mode-27-inch-4k-240hz', 8, 15, CAST(24990000.00 AS Decimal(18, 2)), CAST(22990000.00 AS Decimal(18, 2)), 104, 0, N'Màn hình LG 27 inch Nano IPS 4K, hỗ trợ Dual Mode cho gaming cao cấp.', N'LG 27U Nano IPS Dual Mode là màn hình gaming cao cấp với khả năng chuyển giữa 4K 240Hz và FHD 480Hz. Sản phẩm phù hợp cho người dùng cần tốc độ cao, màu sắc đẹp và độ chi tiết tốt trong không gian màn hình 27 inch.', N'/uploads/products/monitor/lg-27u-nanoips-dual-mode/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (69, N'KB-AKKO-5075B-PLUS-BWTVN', N'Bàn phím AKKO 5075B Plus Black World Tour VIET NAM', N'ban-phim-akko-5075b-plus-black-world-tour-viet-nam', 9, 23, CAST(1790000.00 AS Decimal(18, 2)), NULL, 130, 0, N'Bàn phím cơ AKKO layout 75%, hỗ trợ 3 chế độ kết nối và keycap PBT nổi bật theo chủ đề Việt Nam.', N'AKKO 5075B Plus Black World Tour VIET NAM là mẫu bàn phím cơ hướng đến người dùng yêu thích layout gọn gàng nhưng vẫn cần đầy đủ cụm phím chức năng cơ bản. Sản phẩm hỗ trợ kết nối có dây, Bluetooth và Wireless 2.4GHz, phù hợp cho cả desktop lẫn laptop. Bộ keycap PBT bền màu cùng phối màu đen đỏ trắng tạo điểm nhấn nổi bật cho góc máy. Đây là lựa chọn phù hợp cho gaming, làm việc và người dùng thích bàn phím có cá tính riêng.', N'/uploads/products/keyboard/akko-5075b-plus-black-world-tour-viet-nam/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), CAST(N'2026-04-09T23:07:21.1303630' AS DateTime2))
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (70, N'KB-AULA-F75-WHITE-RED', N'Bàn phím AULA F75 có dây (Trắng Red switch) F7512', N'ban-phim-aula-f75-co-day-trang-red-switch-f7512', 9, 24, CAST(785000.00 AS Decimal(18, 2)), CAST(650000.00 AS Decimal(18, 2)), 124, 0, N'Bàn phím cơ AULA F75 có dây, layout 75%, switch Red và LED RGB phù hợp tầm giá phổ thông.', N'AULA F75 F7512 là mẫu bàn phím cơ có dây với thiết kế 75% nhỏ gọn, phù hợp cho người dùng muốn tối ưu diện tích bàn làm việc nhưng vẫn có trải nghiệm gõ tốt. Phiên bản màu trắng đi kèm Red switch cho cảm giác nhấn nhẹ, phù hợp gõ văn bản lẫn chơi game. Keycap ABS cùng hệ thống LED RGB giúp sản phẩm nổi bật hơn trong phân khúc ngân sách.', N'/uploads/products/keyboard/aula-f75-co-day-trang-red-switch-f7512/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (71, N'KB-DAREU-EK75-RT-BLACK', N'Bàn phím cơ DareU EK75 Rapid Trigger Black', N'ban-phim-co-dareu-ek75-rapid-trigger-black', 9, 25, CAST(2500000.00 AS Decimal(18, 2)), CAST(1750000.00 AS Decimal(18, 2)), 110, 1, N'Bàn phím gaming DareU EK75 Rapid Trigger layout 75% với kết nối USB-C, tối ưu cho game thủ FPS.', N'DareU EK75 Rapid Trigger Black là mẫu bàn phím gaming tập trung vào hiệu năng, hướng đến người chơi cần tốc độ phản hồi cao và khả năng điều khiển chính xác. Layout 75% giúp tiết kiệm diện tích nhưng vẫn giữ lại các phím điều hướng quan trọng. Kết nối USB-C/USB ổn định, keycap PBT Double-Shot bền bỉ và cảm giác gõ chắc chắn khiến đây là lựa chọn đáng chú ý trong phân khúc bàn phím hiệu năng.', N'/uploads/products/keyboard/dareu-ek75-rapid-trigger-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (72, N'KB-DURGOD-CAVALRY-87-BLACK', N'Bàn phím cơ không dây Durgod Cavalry 87 Black Kailh Turbo Silent Red Switch', N'ban-phim-co-khong-day-durgod-cavalry-87-black-kailh-turbo-silent-red-switch', 9, 26, CAST(1690000.00 AS Decimal(18, 2)), CAST(1190000.00 AS Decimal(18, 2)), 109, 0, N'Bàn phím Durgod Cavalry 87 không dây, layout TKL, switch Kailh Turbo Silent Red và thiết kế gọn cho làm việc.', N'Durgod Cavalry 87 Black là bàn phím cơ không dây theo layout TKL/Tenkeyless, phù hợp cho người dùng muốn tiết kiệm không gian nhưng vẫn giữ trải nghiệm gõ ổn định. Phiên bản sử dụng Kailh Turbo Silent Red switch thiên về sự êm ái, thích hợp cho môi trường làm việc hoặc chơi game đêm khuya. Bàn phím hỗ trợ kết nối wireless và USB-C, kết hợp cùng LED RGB giúp hoàn thiện tốt cả yếu tố thẩm mỹ lẫn công năng.', N'/uploads/products/keyboard/durgod-cavalry-87-black-kailh-turbo-silent-red-switch/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (73, N'KB-CORSAIR-K70-PRO-RED', N'Bàn phím Corsair K70 PRO Red Switch', N'ban-phim-corsair-k70-pro-red-switch', 9, 3, CAST(3990000.00 AS Decimal(18, 2)), CAST(3590000.00 AS Decimal(18, 2)), 109, 1, N'Bàn phím cơ Corsair K70 PRO full-size, switch Cherry MX Red, keycap PBT Doubleshot và RGB nổi bật.', N'Corsair K70 PRO Red Switch là mẫu bàn phím cơ full-size dành cho game thủ và người dùng cần đủ cụm numpad để làm việc. Sản phẩm dùng switch Cherry MX Red cho hành trình mượt, phù hợp với nhịp gõ nhanh và chơi game liên tục. Keycap PBT Doubleshot bền bỉ, LED RGB đẹp mắt và kết nối có dây ổn định giúp K70 PRO giữ được vị thế trong phân khúc bàn phím gaming cao cấp.', N'/uploads/products/keyboard/corsair-k70-pro-red-switch/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (74, N'KB-E-DRA-EK3104L-BETA-BROWN', N'Bàn phím E-Dra EK3104L Beta Brown Switch', N'ban-phim-e-dra-ek3104l-beta-brown-switch', 9, 27, CAST(990000.00 AS Decimal(18, 2)), CAST(559000.00 AS Decimal(18, 2)), 127, 1, N'Bàn phím cơ E-Dra EK3104L Beta full-size giá dễ tiếp cận, Brown switch và LED Rainbow.', N'E-Dra EK3104L Beta Brown Switch là mẫu bàn phím cơ phổ thông dành cho người dùng cần một sản phẩm full-size có mức giá dễ tiếp cận. Brown switch cho cảm giác gõ cân bằng giữa làm việc và giải trí, trong khi LED Rainbow tạo điểm nhấn vừa đủ cho góc máy. Kết nối USB ổn định và layout 100% giúp sản phẩm phù hợp với học tập, văn phòng và gaming cơ bản.', N'/uploads/products/keyboard/e-dra-ek3104l-beta-brown-switch/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (75, N'KB-ASUS-ROG-SCOPE-II-96-WL-SNOW', N'Bàn phím Asus ROG Strix Scope II 96 Wireless ROG NX Snow Switch', N'ban-phim-asus-rog-strix-scope-ii-96-wireless-rog-nx-snow-switch', 9, 7, CAST(4990000.00 AS Decimal(18, 2)), CAST(3890000.00 AS Decimal(18, 2)), 108, 0, N'Bàn phím ASUS ROG layout 96%, hỗ trợ ba chế độ kết nối, switch NX Snow và keycap PBT cao cấp.', N'ASUS ROG Strix Scope II 96 Wireless là mẫu bàn phím cơ cao cấp hướng đến game thủ cần trải nghiệm gõ tốt nhưng vẫn muốn một layout nhỏ gọn hơn full-size truyền thống. Bàn phím hỗ trợ Wireless 2.4GHz, Bluetooth và USB-C, cho khả năng dùng linh hoạt trên nhiều thiết bị. Switch ROG NX Snow, keycap PBT và LED RGB Aura Sync giúp sản phẩm đáp ứng tốt cả hiệu năng lẫn yếu tố thẩm mỹ trong hệ sinh thái gaming ASUS.', N'/uploads/products/keyboard/asus-rog-strix-scope-ii-96-wireless-rog-nx-snow-switch/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (76, N'KB-LOGITECH-G913-TKL-CLICKY', N'Bàn phím Logitech G913 TKL Lightspeed Wireless Clicky', N'ban-phim-logitech-g913-tkl-lightspeed-wireless-clicky', 9, 28, CAST(4390000.00 AS Decimal(18, 2)), CAST(3710000.00 AS Decimal(18, 2)), 107, 0, N'Bàn phím Logitech G913 TKL không dây, thiết kế low-profile, kết nối tốc độ cao và switch Clicky cá tính.', N'Logitech G913 TKL Lightspeed Wireless Clicky là mẫu bàn phím cơ low-profile nổi bật với thiết kế mỏng, hiện đại và tối ưu cho góc máy gaming cao cấp. Bàn phím hỗ trợ Wireless 2.4GHz và Bluetooth, phù hợp cho người dùng di chuyển nhiều hoặc thích không gian bàn sạch gọn. Phiên bản Clicky mang lại phản hồi rõ ràng, trong khi hệ thống LED RGB Lightsync tăng thêm trải nghiệm cá nhân hóa.', N'/uploads/products/keyboard/logitech-g913-tkl-lightspeed-wireless-clicky/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (77, N'KB-RAZER-BLACKWIDOW-V4-PRO-GREEN', N'Bàn phím cơ Razer BlackWidow V4 Pro Green Switch', N'ban-phim-co-razer-blackwidow-v4-pro-green-switch', 9, 29, CAST(6190000.00 AS Decimal(18, 2)), CAST(5090000.00 AS Decimal(18, 2)), 106, 0, N'Bàn phím gaming Razer BlackWidow V4 Pro full-size, switch Green, đệm kê tay và RGB Chroma nổi bật.', N'Razer BlackWidow V4 Pro Green Switch là mẫu bàn phím cơ cao cấp dành cho game thủ yêu thích trải nghiệm full-size đầy đủ tính năng. Phiên bản Green switch mang lại cảm giác bấm clicky rõ ràng, phù hợp với người dùng thích phản hồi mạnh tay. Bàn phím dùng kết nối có dây ổn định, keycap Doubleshot ABS bền bỉ, hỗ trợ RGB Chroma và thiết kế nổi bật cho các bộ PC gaming cao cấp.', N'/uploads/products/keyboard/razer-blackwidow-v4-pro-green-switch/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (78, N'KB-RAPOO-V700-A8-DARKGREY-BLUE', N'Bàn phím Rapoo V700-A8 Dark Grey Blue Switch', N'ban-phim-rapoo-v700-a8-dark-grey-blue-switch', 9, 30, CAST(1899000.00 AS Decimal(18, 2)), CAST(1090000.00 AS Decimal(18, 2)), 113, 0, N'Bàn phím Rapoo V700-A8 layout 84%, hỗ trợ ba chế độ kết nối và switch Blue phù hợp người thích cảm giác gõ rõ.', N'Rapoo V700-A8 Dark Grey Blue Switch là bàn phím cơ hướng đến người dùng muốn một layout 84% cân bằng giữa gọn gàng và đủ cụm phím cần thiết. Sản phẩm hỗ trợ kết nối có dây, Bluetooth và Wireless 2.4GHz, dễ dàng dùng cho nhiều thiết bị khác nhau. Phiên bản Blue switch cho phản hồi clicky rõ ràng, phù hợp với người dùng thích cảm giác gõ nổi bật và cá tính hơn.', N'/uploads/products/keyboard/rapoo-v700-a8-dark-grey-blue-switch/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (79, N'MOU-LOGITECH-G502-HERO-BLACK', N'Chuột Logitech G502 HERO Black', N'chuot-logitech-g502-hero-black', 10, 28, CAST(1390000.00 AS Decimal(18, 2)), CAST(1090000.00 AS Decimal(18, 2)), 116, 0, N'Chuột gaming Logitech G502 HERO có dây, cảm biến HERO, 11 nút, RGB và DPI lên đến 25.600.', N'Logitech G502 HERO Black là mẫu chuột gaming có dây nổi tiếng với thiết kế công thái học dành cho tay phải và hệ thống nút bấm phong phú. Cảm biến HERO cho độ chính xác cao, hỗ trợ DPI tối đa 25.600 và phần mềm G HUB giúp tùy biến sâu theo nhu cầu chơi game lẫn làm việc.', N'/uploads/products/mouse/logitech-g502-hero-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (80, N'MOU-LOGITECH-G502X-PLUS-WHITE', N'Chuột Logitech G502 X Plus White', N'chuot-logitech-g502-x-plus-white', 10, 28, CAST(4290000.00 AS Decimal(18, 2)), CAST(3690000.00 AS Decimal(18, 2)), 110, 0, N'Chuột Logitech G502 X Plus không dây màu trắng, cảm biến HERO 25K, switch Lightforce và pin lâu dài.', N'Logitech G502 X Plus White là mẫu chuột không dây cao cấp với thiết kế công thái học cho tay phải, cảm biến HERO 25K và switch Lightforce hiện đại. Sản phẩm hỗ trợ kết nối 2.4GHz và sạc USB-C, phù hợp cho game thủ cần hiệu năng cao, nhiều nút tùy chỉnh và ngoại hình nổi bật.', N'/uploads/products/mouse/logitech-g502x-plus-white/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (81, N'MOU-ATK-PAW3950-WHITE', N'Chuột ATK PAW3950 Wireless White', N'chuot-atk-paw3950-wireless-white', 10, 31, CAST(2490000.00 AS Decimal(18, 2)), CAST(2190000.00 AS Decimal(18, 2)), 114, 0, N'Chuột ATK siêu nhẹ đa kết nối, cảm biến Pixart PAW3950, trọng lượng khoảng 49g và pin 75 giờ.', N'ATK PAW3950 Wireless White là mẫu chuột siêu nhẹ hướng đến game thủ FPS cần tốc độ và sự linh hoạt. Cảm biến Pixart PAW3950 hỗ trợ DPI rất cao, form đối xứng dễ làm quen và kết nối đa chế độ giúp sản phẩm phù hợp cả gaming lẫn sử dụng hằng ngày.', N'/uploads/products/mouse/atk-paw3950-wireless-white/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (82, N'MOU-HYPERX-26K-WIRELESS-WHITE', N'Chuột HyperX 26K Wireless White', N'chuot-hyperx-26k-wireless-white', 10, 32, CAST(2890000.00 AS Decimal(18, 2)), CAST(2490000.00 AS Decimal(18, 2)), 112, 0, N'Chuột HyperX không dây cảm biến 26K, trọng lượng 59g, RGB và pin đến 100 giờ.', N'HyperX 26K Wireless White là mẫu chuột gaming nhẹ, phù hợp cho người dùng yêu thích form đối xứng và kết nối đa thiết bị. Cảm biến HyperX 26K, switch bền bỉ và thời lượng pin dài giúp sản phẩm đáp ứng tốt cả nhu cầu chơi game nhanh lẫn sử dụng di động.', N'/uploads/products/mouse/hyperx-26k-wireless-white/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (83, N'MOU-RAPOO-26K-WIRELESS-WHITE', N'Chuột Rapoo 26K Wireless White', N'chuot-rapoo-26k-wireless-white', 10, 30, CAST(1990000.00 AS Decimal(18, 2)), CAST(1690000.00 AS Decimal(18, 2)), 113, 0, N'Chuột Rapoo không dây màu trắng, cảm biến PixArt 26K, polling rate 8000Hz và pin rất dài.', N'Rapoo 26K Wireless White là mẫu chuột công thái học hiệu năng cao, nổi bật với polling rate lên tới 8000Hz và cảm biến PixArt 26K. Thiết kế nhẹ, pin bền và kết nối không dây giúp sản phẩm phù hợp cho cả game thủ lẫn người dùng chuyên làm việc cần chuột phản hồi nhanh.', N'/uploads/products/mouse/rapoo-26k-wireless-white/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (84, N'MOU-GLORIOUS-WIRED-BLACK', N'Chuột Glorious Wired Black', N'chuot-glorious-wired-black', 10, 35, CAST(1590000.00 AS Decimal(18, 2)), CAST(1390000.00 AS Decimal(18, 2)), 109, 0, N'Chuột Glorious có dây màu đen với form ergonomic, phù hợp gaming và làm việc lâu dài.', N'Glorious Wired Black là mẫu chuột có dây hướng đến trải nghiệm đơn giản, ổn định và dễ làm quen. Form công thái học giúp cầm nắm thoải mái, phù hợp cho người dùng chơi game nhiều giờ hoặc làm việc cần thao tác chính xác liên tục.', N'/uploads/products/mouse/glorious-wired-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (85, N'MOU-ASUS-ROG-AIMPOINT-PRO-BLACK', N'Chuột ASUS ROG AimPoint Pro Wireless Black', N'chuot-asus-rog-aimpoint-pro-wireless-black', 10, 7, CAST(3490000.00 AS Decimal(18, 2)), CAST(3090000.00 AS Decimal(18, 2)), 111, 0, N'Chuột ASUS ROG không dây cảm biến AimPoint Pro 42.000 DPI, siêu nhẹ và polling rate tối đa 8000Hz.', N'ASUS ROG AimPoint Pro Wireless Black là mẫu chuột gaming cao cấp với thiết kế công thái học, kết nối linh hoạt và cảm biến quang học độ chính xác cao. Polling rate tối đa 8000Hz cùng switch bền bỉ giúp sản phẩm phù hợp cho game thủ FPS và người dùng cần độ phản hồi nhanh.', N'/uploads/products/mouse/asus-rog-aimpoint-pro-wireless-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (86, N'MOU-DAREU-BRAVO-WIRELESS-BLACK', N'Chuột DareU BRAVO Wireless Black', N'chuot-dareu-bravo-wireless-black', 10, 25, CAST(690000.00 AS Decimal(18, 2)), CAST(590000.00 AS Decimal(18, 2)), 117, 1, N'Chuột DareU BRAVO đa kết nối, cảm biến BRAVO ATG4090, RGB và kích thước gọn dễ dùng.', N'DareU BRAVO Wireless Black là mẫu chuột giá tốt, thiết kế đối xứng và hỗ trợ đa kết nối linh hoạt. Cảm biến BRAVO (ATG4090), LED RGB cùng phụ kiện đi kèm cơ bản giúp đây là lựa chọn phù hợp cho người dùng phổ thông và gaming nhẹ.', N'/uploads/products/mouse/dareu-bravo-wireless-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (87, N'MOU-CORSAIR-WIRELESS-BLACK', N'Chuột Corsair Wireless Black', N'chuot-corsair-wireless-black', 10, 3, CAST(2790000.00 AS Decimal(18, 2)), CAST(2390000.00 AS Decimal(18, 2)), 108, 0, N'Chuột Corsair không dây màu đen, form thuận tay phải và dùng pin sạc Li-ion.', N'Corsair Wireless Black là mẫu chuột không dây mang thiết kế công thái học cho tay phải, phù hợp cả chơi game lẫn sử dụng hằng ngày. Dữ liệu gốc cung cấp các thông tin chính về form, kết nối và loại pin, đủ để dùng làm seed data cho danh mục chuột không dây.', N'/uploads/products/mouse/corsair-wireless-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (88, N'MOU-RAZER-WIRELESS-BLACK', N'Chuột Razer Wireless Black', N'chuot-razer-wireless-black', 10, 29, CAST(2990000.00 AS Decimal(18, 2)), CAST(2690000.00 AS Decimal(18, 2)), 108, 1, N'Chuột Razer màu đen thiết kế ergonomic, đa kết nối và sử dụng pin sạc Li-ion.', N'Razer Wireless Black là mẫu chuột được xây dựng cho người dùng ưa thiết kế công thái học và khả năng kết nối linh hoạt. Đây là sản phẩm phù hợp để mở rộng seed data cho danh mục gaming gear, với các thông tin cơ bản về form, màu sắc và nguồn pin sạc.', N'/uploads/products/mouse/razer-wireless-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (89, N'HS-ASUS-ROG-PELTA-WL-RGB-BLACK', N'Tai nghe ASUS ROG Pelta WL RGB Black', N'tai-nghe-asus-rog-pelta-wl-rgb-black', 11, 7, CAST(4570000.00 AS Decimal(18, 2)), CAST(3190000.00 AS Decimal(18, 2)), 111, 1, N'Tai nghe gaming ASUS ROG Pelta không dây, driver titanium 50mm, RGB và pin lên đến 70 giờ.', N'ASUS ROG Pelta WL RGB Black là mẫu tai nghe gaming cao cấp với thiết kế over-ear, kết nối linh hoạt và hệ thống đèn Aura Sync. Driver titanium 50mm, trọng lượng nhẹ khoảng 309g và pin dài đến 70 giờ khiến đây là lựa chọn đáng chú ý cho game thủ chơi trên PC và nhiều nền tảng.', N'/uploads/products/headset/asus-rog-pelta-wl-rgb-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (90, N'HS-EDIFIER-W830NB-BLACK', N'Tai nghe Edifier W830NB Black', N'tai-nghe-edifier-w830nb-black', 11, 33, CAST(1690000.00 AS Decimal(18, 2)), CAST(1490000.00 AS Decimal(18, 2)), 118, 2, N'Tai nghe Edifier W830NB không dây màu đen, kiểu over-ear và sạc Type-C tiện dụng.', N'Edifier W830NB Black là mẫu tai nghe không dây over-ear có thiết kế hiện đại, phù hợp nghe nhạc, làm việc và sử dụng di động. Sản phẩm hỗ trợ Bluetooth, dùng cổng sạc Type-C và phù hợp cho người dùng cần một chiếc tai nghe gọn gàng trong phân khúc dễ tiếp cận.', N'/uploads/products/headset/edifier-w830nb-black/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (91, N'HS-LOGITECH-G435-LIGHTSPEED-WHITE', N'Tai nghe Logitech G435 Lightspeed Wireless White', N'tai-nghe-logitech-g435-lightspeed-wireless-white', 11, 28, CAST(2000000.00 AS Decimal(18, 2)), CAST(1390000.00 AS Decimal(18, 2)), 118, 0, N'Tai nghe Logitech G435 không dây màu trắng, hỗ trợ Lightspeed/Bluetooth và thiết kế nhẹ đeo thoải mái.', N'Logitech G435 Lightspeed Wireless White là mẫu tai nghe gaming không dây nổi bật với thiết kế trẻ trung, trọng lượng nhẹ và khả năng kết nối linh hoạt. Sản phẩm phù hợp cho người dùng PC, laptop và thiết bị di động cần một chiếc headset chơi game lẫn giải trí hằng ngày.', N'/uploads/products/headset/logitech-g435-lightspeed-wireless-white/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (92, N'HS-RAPOO-VH600', N'Tai nghe Rapoo Gaming VH600', N'tai-nghe-rapoo-gaming-vh600', 11, 30, CAST(1390000.00 AS Decimal(18, 2)), CAST(890000.00 AS Decimal(18, 2)), 115, 0, N'Tai nghe Rapoo VH600 có dây qua USB, thiết kế over-ear phù hợp gaming và giải trí cơ bản.', N'Rapoo Gaming VH600 là tai nghe gaming có dây dùng cổng USB, thiết kế over-ear cho cảm giác đeo ổn định và cách âm tốt hơn. Đây là lựa chọn phù hợp cho người dùng cần một chiếc headset dễ dùng, mức giá hợp lý và tương thích tốt với hệ thống PC chơi game.', N'/uploads/products/headset/rapoo-gaming-vh600/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (93, N'HS-ONIKUMA-B5-TRIMODE-WHITE', N'Tai nghe Onikuma Tai Mèo B5 RGB Tri Mode Trắng', N'tai-nghe-onikuma-tai-meo-b5-rgb-tri-mode-trang', 11, 34, CAST(1190000.00 AS Decimal(18, 2)), CAST(990000.00 AS Decimal(18, 2)), 117, 0, N'Tai nghe Onikuma B5 phong cách tai mèo, RGB, hỗ trợ kết nối Bluetooth/có dây và thiết kế over-ear.', N'Onikuma Tai Mèo B5 RGB Tri Mode Trắng là mẫu tai nghe nổi bật với ngoại hình dễ thương và đèn RGB bắt mắt. Sản phẩm hỗ trợ nhiều kiểu kết nối và phù hợp cho người dùng thích phong cách setup trẻ trung, giải trí và gaming cơ bản.', N'/uploads/products/headset/onikuma-b5-tri-mode-white/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (94, N'HS-RAZER-BLACKSHARK-V3PRO-CS2', N'Tai nghe Razer Blackshark V3 Pro Counter-Strike 2 Edition', N'tai-nghe-razer-blackshark-v3-pro-counter-strike-2-edition', 11, 29, CAST(8290000.00 AS Decimal(18, 2)), NULL, 108, 0, N'Tai nghe Razer Blackshark V3 Pro bản Counter-Strike 2 Edition, kiểu over-ear và dùng kết nối qua USB-A.', N'Razer Blackshark V3 Pro Counter-Strike 2 Edition là mẫu tai nghe gaming phiên bản đặc biệt, hướng đến game thủ yêu thích thiết kế đậm chất esports. Dữ liệu ảnh cho thấy sản phẩm dùng cổng USB-A và tích hợp công nghệ micro HyperClear Super Wideband, phù hợp để làm seed data cho nhóm headset cao cấp.', N'/uploads/products/headset/razer-blackshark-v3-pro-cs2-edition/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (95, N'HS-CORSAIR-VIRTUOSO-SE-ESPRESSO', N'Tai nghe Corsair Virtuoso RGB Wireless SE Espresso', N'tai-nghe-corsair-virtuoso-rgb-wireless-se-espresso', 11, 3, CAST(5600000.00 AS Decimal(18, 2)), CAST(5490000.00 AS Decimal(18, 2)), 100, 10, N'Tai nghe Corsair Virtuoso RGB Wireless SE màu Espresso, đa kết nối và thiết kế over-ear cao cấp.', N'Corsair Virtuoso RGB Wireless SE Espresso là tai nghe over-ear cao cấp với thiết kế sang trọng và kết nối rất linh hoạt. Sản phẩm hỗ trợ 2.4GHz, Bluetooth và USB, phù hợp cho người dùng cần một chiếc headset phục vụ đồng thời gaming, giải trí và làm việc.', N'/uploads/products/headset/corsair-virtuoso-rgb-wireless-se-espresso/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (96, N'HS-HYPERX-CLOUD-STINGER-CORE-II', N'Tai nghe HyperX Cloud Stinger Core II', N'tai-nghe-hyperx-cloud-stinger-core-ii', 11, 32, CAST(990000.00 AS Decimal(18, 2)), CAST(790000.00 AS Decimal(18, 2)), 122, 0, N'Tai nghe HyperX Cloud Stinger Core II có dây, kết nối 3.5mm và thiết kế over-ear dễ dùng.', N'HyperX Cloud Stinger Core II là mẫu tai nghe có dây phù hợp cho nhu cầu gaming phổ thông, học tập và giải trí. Kết nối 3.5mm đơn giản, form over-ear thoải mái và thương hiệu HyperX quen thuộc giúp sản phẩm dễ tiếp cận với nhiều người dùng.', N'/uploads/products/headset/hyperx-cloud-stinger-core-ii/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (97, N'NET-ASUS-RT-AC1500UHP', N'Bộ định tuyến WiFi 5 ASUS RT-AC1500UHP Chuẩn AC1500 (Xuyên tường)', N'bo-dinh-tuyen-wifi-5-asus-rt-ac1500uhp-chuan-ac1500-xuyen-tuong', 12, 7, CAST(1990000.00 AS Decimal(18, 2)), CAST(1690000.00 AS Decimal(18, 2)), 117, 1, N'Router ASUS RT-AC1500UHP chuẩn WiFi 5 AC1500, 4 anten, tối ưu cho game và phủ sóng ổn định.', N'ASUS RT-AC1500UHP là bộ định tuyến WiFi 5 hướng đến nhu cầu dùng mạng gia đình và văn phòng nhỏ. Sản phẩm hỗ trợ chuẩn 802.11ac tốc độ tối đa 1500Mbps, MU-MIMO và các tính năng tối ưu cho game. Thiết kế nhiều anten giúp tăng khả năng phủ sóng, phù hợp cho người dùng cần một router xuyên tường ổn định trong tầm giá tốt.', N'/uploads/products/network/asus-rt-ac1500uhp/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (98, N'NET-ASUS-XT8-W2PK', N'Thiết bị định tuyến mạng không dây Asus XT8 (W-2-PK)', N'thiet-bi-dinh-tuyen-mang-khong-day-asus-xt8-w-2-pk', 12, 7, CAST(13990000.00 AS Decimal(18, 2)), CAST(10990000.00 AS Decimal(18, 2)), 107, 0, N'Hệ thống mesh WiFi 6 ASUS XT8 2 pack, tốc độ đến 6000Mbps, phủ sóng rộng và quản lý dễ qua app.', N'ASUS XT8 (W-2-PK) là bộ mesh WiFi cao cấp dành cho nhà nhiều tầng, căn hộ lớn hoặc không gian cần độ phủ sóng mạnh và liền mạch. Sản phẩm hỗ trợ chuẩn WiFi 6 với tốc độ tối đa 6000Mbps, quản lý bằng ứng dụng và hỗ trợ tối đa khoảng 60 thiết bị. Đây là lựa chọn phù hợp cho người dùng cần mạng ổn định cho học tập, làm việc, xem phim 4K và gaming trong toàn bộ ngôi nhà.', N'/uploads/products/network/asus-xt8-w-2-pk/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (99, N'NET-ASUS-RT-AX92U-2PACK', N'Thiết bị mạng AiMesh AX6100 WiFi System (RT-AX92U 2 Pack)', N'thiet-bi-mang-aimesh-ax6100-wifi-system-rt-ax92u-2-pack', 12, 7, CAST(15990000.00 AS Decimal(18, 2)), CAST(13990000.00 AS Decimal(18, 2)), 106, 0, N'Hệ thống WiFi ASUS AiMesh AX6100 gồm 2 thiết bị, hướng đến gaming và mạng gia đình hiệu năng cao.', N'ASUS RT-AX92U 2 Pack là hệ thống AiMesh WiFi System thuộc phân khúc cao cấp, phù hợp cho người dùng cần vùng phủ lớn và độ ổn định cao. Chuẩn AX6100 giúp hệ thống đáp ứng tốt cho gaming, streaming và dùng nhiều thiết bị cùng lúc. Thiết kế 2 pack hỗ trợ mở rộng vùng phủ sóng linh hoạt trong nhà ở hoặc văn phòng hiện đại.', N'/uploads/products/network/asus-rt-ax92u-2-pack/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (100, N'NET-ASUS-RT-AC1300UHP', N'Thiết bị mạng không dây ASUS RT-AC1300UHP', N'thiet-bi-mang-khong-day-asus-rt-ac1300uhp', 12, 7, CAST(2190000.00 AS Decimal(18, 2)), CAST(1790000.00 AS Decimal(18, 2)), 116, 0, N'Router ASUS RT-AC1300UHP chuẩn AC1300, MU-MIMO, tối ưu cho game và bảo mật mạng gia đình.', N'ASUS RT-AC1300UHP là router không dây dành cho nhu cầu sử dụng hằng ngày với điểm mạnh ở độ ổn định, phủ sóng tốt và giá hợp lý. Sản phẩm hỗ trợ MU-MIMO, bộ xử lý bốn nhân và các tính năng bảo mật đến từ Trend Micro. Đây là mẫu router phù hợp cho gia đình, phòng trọ cao cấp hoặc văn phòng nhỏ cần mạng 2 băng tần ổn định.', N'/uploads/products/network/asus-rt-ac1300uhp/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
GO
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (101, N'NET-ASUS-RT-AC59U-AC1500', N'Bộ định tuyến ASUS RT-AC59U Mobile Gaming AC1500 MU-MIMO 2 băng tần', N'bo-dinh-tuyen-asus-rt-ac59u-mobile-gaming-ac1500-mu-mimo-2-bang-tan', 12, 7, CAST(1950000.00 AS Decimal(18, 2)), CAST(949000.00 AS Decimal(18, 2)), 120, 0, N'Router ASUS RT-AC59U AC1500 2 băng tần, hỗ trợ MU-MIMO và tối ưu cho nhu cầu mobile gaming.', N'ASUS RT-AC59U là mẫu router 2 băng tần hướng đến người dùng cần một thiết bị mạng giá tốt nhưng vẫn đủ ổn định cho học tập, làm việc và chơi game trên di động. Chuẩn AC1500 cùng công nghệ MU-MIMO giúp chia tải tốt hơn khi có nhiều thiết bị truy cập. Sản phẩm phù hợp cho căn hộ nhỏ, phòng riêng hoặc người dùng cần bộ định tuyến dễ thiết lập và sử dụng.', N'/uploads/products/network/asus-rt-ac59u-mobile-gaming-ac1500/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (102, N'ACC-APPLE-SMARTKEYBOARD-IPAD129-4GEN', N'Apple Smart Keyboard Folio for iPad Pro 12.9 inch (4th generation) - US English', N'apple-smart-keyboard-folio-for-ipad-pro-12-9-inch-4th-generation-us-english', 13, 37, CAST(6000000.00 AS Decimal(18, 2)), CAST(5700000.00 AS Decimal(18, 2)), 100, 34, N'Bàn phím Apple Smart Keyboard Folio cho iPad Pro 12.9 inch 4th gen, kết nối Smart Connector tiện dụng.', N'Apple Smart Keyboard Folio là phụ kiện bàn phím cao cấp dành cho iPad Pro 12.9 inch thế hệ thứ 4. Sản phẩm sử dụng Smart Connector nên không cần sạc hay ghép nối Bluetooth, đồng thời hoạt động như một lớp cover bảo vệ mỏng nhẹ. Đây là lựa chọn phù hợp cho người dùng iPad cần gõ văn bản nhiều và muốn trải nghiệm gần như laptop trong hệ sinh thái Apple.', N'/uploads/products/accessories/apple-smart-keyboard-folio-ipad-pro-129-4th-gen/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), CAST(N'2026-04-09T23:06:35.8458180' AS DateTime2))
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (103, N'ACC-UGREEN-NEXODE-200W-CD271', N'Bộ sạc nhanh GaN Nexode 200W Ugreen CD271 40913', N'bo-sac-nhanh-gan-nexode-200w-ugreen-cd271-40913', 13, 38, CAST(2790000.00 AS Decimal(18, 2)), CAST(1750000.00 AS Decimal(18, 2)), 112, 0, N'Bộ sạc Ugreen Nexode GaN 200W hỗ trợ sạc đồng thời nhiều thiết bị, phù hợp laptop và hệ di động.', N'Ugreen Nexode CD271 40913 là bộ sạc nhanh GaN công suất lớn dành cho người dùng có nhiều thiết bị cần sạc cùng lúc. Tổng công suất 200W cho phép sạc laptop, tablet và điện thoại trong một bộ sạc gọn gàng, tiết kiệm không gian ổ cắm. Công nghệ GaN II cùng cơ chế sạc thông minh giúp tăng hiệu suất và nâng cao độ an toàn khi sử dụng lâu dài.', N'/uploads/products/accessories/ugreen-nexode-200w-cd271-40913/thumb.jpg', 18, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (104, N'ACC-UGREEN-HUB-5IN1-CM136', N'Cổng chuyển đổi USB C Ugreen 5 in 1 CM136 50209', N'cong-chuyen-doi-usb-c-ugreen-5-in-1-cm136-50209', 13, 38, CAST(890000.00 AS Decimal(18, 2)), CAST(690000.00 AS Decimal(18, 2)), 124, 0, N'Hub Ugreen 5 trong 1 qua USB-C, hỗ trợ HDMI 4K, USB 3.0 và sạc PD tiện cho laptop mỏng nhẹ.', N'Ugreen CM136 50209 là hub mở rộng cổng kết nối dành cho laptop, tablet hoặc điện thoại có USB-C. Sản phẩm cung cấp 3 cổng USB 3.0, 1 cổng HDMI và 1 cổng USB-C hỗ trợ PD, rất phù hợp để trình chiếu, dùng chuột/USB và sạc cùng lúc. Thiết kế nhỏ gọn, chất liệu kim loại cùng khả năng xuất hình 4K 30Hz giúp đây là phụ kiện hữu ích cho học tập, làm việc và di chuyển.', N'/uploads/products/accessories/ugreen-usb-c-hub-5-in-1-cm136-50209/thumb.jpg', 18, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (105, N'ACC-UGREEN-GAN-100W-CD226', N'Củ sạc Ugreen GaN 100W CD226 40747', N'cu-sac-ugreen-gan-100w-cd226-40747', 13, 38, CAST(1260000.00 AS Decimal(18, 2)), CAST(990000.00 AS Decimal(18, 2)), 118, 0, N'Củ sạc Ugreen GaN 100W nhỏ gọn, hỗ trợ nhiều cổng sạc cho laptop, tablet và điện thoại.', N'Ugreen GaN 100W CD226 40747 là củ sạc nhanh công suất cao dành cho người dùng cần một giải pháp sạc gọn gàng khi đi làm hoặc đi công tác. Sản phẩm hỗ trợ nhiều cổng đầu ra, phù hợp cho laptop, tablet và điện thoại hiện đại. Công nghệ GaN giúp giảm kích thước bộ sạc nhưng vẫn duy trì hiệu suất tốt và an toàn khi sử dụng.', N'/uploads/products/accessories/ugreen-gan-100w-cd226-40747/thumb.jpg', 18, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (106, N'ACC-MAZER-USBC-VGA-MUSBCAL351', N'Bộ chuyển đổi Mazer ALU USB-C to VGA 1080P Adapter M-USBCAL351-GY', N'bo-chuyen-doi-mazer-alu-usb-c-to-vga-1080p-adapter-m-usbcal351-gy', 13, 39, CAST(520000.00 AS Decimal(18, 2)), CAST(190000.00 AS Decimal(18, 2)), 130, 0, N'Adapter Mazer chuyển từ USB-C sang VGA, hỗ trợ xuất hình 1080P cho máy chiếu và màn hình cũ.', N'Mazer ALU USB-C to VGA Adapter M-USBCAL351-GY là phụ kiện chuyển đổi nhỏ gọn dành cho laptop hoặc tablet có cổng USB-C. Sản phẩm hỗ trợ xuất tín hiệu VGA độ phân giải 1080P, phù hợp cho phòng họp, lớp học hoặc hệ thống trình chiếu dùng màn hình đời cũ. Thiết kế dạng nhôm và dây ngắn giúp adapter bền bỉ, dễ mang theo và phù hợp dùng hằng ngày.', N'/uploads/products/accessories/mazer-alu-usb-c-to-vga-1080p-adapter-m-usbcal351-gy/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (107, N'SW-MICROSOFT-WIN11-HOME-KW900664', N'Phần mềm Microsoft Windows 11 Home ESD KW9-00664', N'phan-mem-microsoft-windows-11-home-esd-kw9-00664', 14, 36, CAST(3690000.00 AS Decimal(18, 2)), CAST(3190000.00 AS Decimal(18, 2)), 220, 0, N'Bản quyền điện tử Windows 11 Home 32-bit/64-bit, ngôn ngữ đa dạng và kích hoạt linh hoạt.', N'Microsoft Windows 11 Home ESD KW9-00664 là bản quyền điện tử dành cho người dùng cá nhân cần hệ điều hành chính hãng cho PC hoặc laptop. Phiên bản hỗ trợ cả 32-bit và 64-bit, đa ngôn ngữ và có thể kích hoạt lại khi thay đổi phần cứng theo thông tin từ ảnh sản phẩm. Đây là lựa chọn phù hợp cho máy gia đình, học tập và làm việc phổ thông.', N'/uploads/products/software/windows-11-home-esd-kw9-00664/thumb.jpg', 0, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (108, N'SW-MICROSOFT-WIN11-PRO-FQC10572', N'Phần mềm Microsoft Windows 11 Pro ESD FQC-10572', N'phan-mem-microsoft-windows-11-pro-esd-fqc-10572', 14, 36, CAST(5590000.00 AS Decimal(18, 2)), CAST(4850000.00 AS Decimal(18, 2)), 190, 0, N'Bản quyền điện tử Windows 11 Pro dành cho người dùng chuyên nghiệp, hỗ trợ 32-bit/64-bit.', N'Microsoft Windows 11 Pro ESD FQC-10572 là bản quyền điện tử phù hợp cho doanh nghiệp nhỏ, người dùng chuyên nghiệp và máy tính làm việc cần nhiều tính năng quản trị hơn bản Home. Sản phẩm hỗ trợ cả 32-bit và 64-bit, đa ngôn ngữ và có thể kích hoạt lại khi thay đổi phần cứng theo mô tả từ ảnh sản phẩm. Đây là phiên bản phù hợp cho môi trường làm việc cần độ tin cậy và tính chính hãng lâu dài.', N'/uploads/products/software/windows-11-pro-esd-fqc-10572/thumb.jpg', 0, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (109, N'SW-MICROSOFT-OFFICEHOME2024-EP206796', N'Phần mềm Microsoft Office Home 2024 EP2-06796', N'phan-mem-microsoft-office-home-2024-ep2-06796', 14, 36, CAST(3590000.00 AS Decimal(18, 2)), CAST(2990000.00 AS Decimal(18, 2)), 179, 1, N'Bản quyền Office Home 2024 cho nhu cầu học tập và làm việc văn phòng cơ bản.', N'Microsoft Office Home 2024 EP2-06796 là gói phần mềm văn phòng bản quyền phù hợp cho người dùng cá nhân, học sinh sinh viên và hộ gia đình. Sản phẩm là key điện tử, được thiết kế cho các tác vụ văn phòng cơ bản và không thể hoàn lại sau khi mua theo thông tin từ ảnh sản phẩm. Đây là lựa chọn phù hợp để sử dụng Word, Excel và các công cụ Office quen thuộc trong thời gian dài.', N'/uploads/products/software/office-home-2024-ep2-06796/thumb.jpg', 0, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (110, N'SW-MICROSOFT-365PERSONAL-EP232313', N'Phần mềm Microsoft 365 Personal 1 năm EP2-32313', N'phan-mem-microsoft-365-personal-1-nam-ep2-32313', 14, 36, CAST(2090000.00 AS Decimal(18, 2)), CAST(1690000.00 AS Decimal(18, 2)), 240, 0, N'Gói Microsoft 365 Personal 1 năm cho 1 người dùng, tối đa 5 thiết bị và tích hợp AI Copilot.', N'Microsoft 365 Personal EP2-32313 là gói thuê bao bản quyền phù hợp cho người dùng cá nhân cần sử dụng bộ Office luôn cập nhật. Sản phẩm có thời hạn 1 năm, dùng cho 1 tài khoản với tối đa 5 thiết bị và tích hợp AI Copilot theo thông tin hiển thị trên ảnh. Đây là lựa chọn phù hợp cho học tập, làm việc từ xa và sử dụng Office đa nền tảng cùng OneDrive/đám mây của Microsoft.', N'/uploads/products/software/microsoft-365-personal-ep2-32313/thumb.jpg', 0, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (111, N'SW-MICROSOFT-365FAMILY-EP236890', N'Phần mềm Microsoft 365 Family 1 năm EP2-36890', N'phan-mem-microsoft-365-family-1-nam-ep2-36890', 14, 36, CAST(2590000.00 AS Decimal(18, 2)), CAST(1990000.00 AS Decimal(18, 2)), 194, 1, N'Gói Microsoft 365 Family 1 năm cho tối đa 6 người dùng, 30 thiết bị và có AI Copilot.', N'Microsoft 365 Family EP2-36890 là gói bản quyền thuê bao dành cho gia đình hoặc nhóm người dùng cần chia sẻ quyền sử dụng Office. Gói có thời hạn 1 năm, hỗ trợ tối đa 6 người dùng với tổng cộng 30 thiết bị và tích hợp AI Copilot theo ảnh sản phẩm. Đây là lựa chọn phù hợp cho gia đình, nhóm học tập hoặc hộ kinh doanh nhỏ muốn dùng Office bản quyền linh hoạt và tiết kiệm hơn.', N'/uploads/products/software/microsoft-365-family-ep2-36890/thumb.jpg', 0, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
