INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (118, N'LAP-LENOVO-THINKPAD-X9-15GEN1-21Q60055VN', N'Laptop Lenovo ThinkPad X9-15 Gen 1 21Q60055VN', N'laptop-lenovo-thinkpad-x9-15-gen-1-21q60055vn', 15, 40, CAST(55129000.00 AS Decimal(18, 2)), CAST(49990000.00 AS Decimal(18, 2)), 105, 0, N'Laptop Lenovo ThinkPad X9-15 Gen 1, Core Ultra 7 258V, Intel Arc 140V, RAM 32GB, SSD 1TB, màn 15.6 inch.', N'ThinkPad X9-15 Gen 1 21Q60055VN là mẫu laptop doanh nhân cao cấp với Intel Core Ultra 7, RAM LPDDR5x 32GB, SSD 1TB và thiết kế mỏng nhẹ cho công việc chuyên nghiệp.', N'/uploads/products/laptop/lenovo-thinkpad-x9-15-gen-1-21q60055vn/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (119, N'LAP-MSI-PRESTIGE16-AI-B2VMG-088VN', N'Laptop MSI Prestige 16 AI+ Mercedes AMG B2VMG 088VN', N'laptop-msi-prestige-16-ai-mercedes-amg-b2vmg-088vn', 15, 10, CAST(49990000.00 AS Decimal(18, 2)), CAST(47990000.00 AS Decimal(18, 2)), 104, 0, N'Laptop MSI Prestige 16 AI+, Core Ultra 9 288V, Intel Arc, RAM 32GB, SSD 2TB, màn 16 inch.', N'MSI Prestige 16 AI+ Mercedes AMG B2VMG 088VN là laptop cao cấp thiên về di động và sáng tạo nội dung với Intel Core Ultra 9, RAM lớn, SSD 2TB và thiết kế hợp tác Mercedes-AMG sang trọng.', N'/uploads/products/laptop/msi-prestige-16-ai-mercedes-amg-b2vmg-088vn/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (120, N'LAP-ACER-SWIFTGO-SFG14-74T-55HD', N'Laptop Acer Swift Go SFG14 74T 55HD', N'laptop-acer-swift-go-sfg14-74t-55hd', 15, 12, CAST(32490000.00 AS Decimal(18, 2)), CAST(31490000.00 AS Decimal(18, 2)), 109, 0, N'Laptop Acer Swift Go 14, Core Ultra 5 225H, Intel Arc 130T, RAM 16GB, SSD 1TB, màn 14 inch.', N'Acer Swift Go SFG14 74T 55HD là mẫu laptop mỏng nhẹ dành cho học tập và làm việc hiện đại với Intel Core Ultra 5, GPU Intel Arc và SSD 1TB tốc độ cao.', N'/uploads/products/laptop/acer-swift-go-sfg14-74t-55hd/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (121, N'LAP-ASUS-ZENBOOK14-UM3406KA-PP555WS', N'Laptop ASUS Zenbook 14 UM3406KA PP555WS', N'laptop-asus-zenbook-14-um3406ka-pp555ws', 15, 7, CAST(31990000.00 AS Decimal(18, 2)), NULL, 107, 0, N'Laptop ASUS Zenbook 14, Ryzen AI 7 350, AMD Radeon, RAM 16GB, SSD 512GB, màn 14 inch.', N'ASUS Zenbook 14 UM3406KA PP555WS là laptop mỏng nhẹ cao cấp hướng đến người dùng văn phòng và sáng tạo với vi xử lý AMD Ryzen AI, thiết kế gọn nhẹ và trải nghiệm di động linh hoạt.', N'/uploads/products/laptop/asus-zenbook-14-um3406ka-pp555ws/thumb.jpg', 24, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (122, N'SPK-LOGITECH-G560', N'Loa Logitech G560', N'loa-logitech-g560', 16, 28, CAST(4890000.00 AS Decimal(18, 2)), CAST(4250000.00 AS Decimal(18, 2)), 110, 0, N'Loa vi tính Logitech G560 với Bluetooth 4.1, LED RGB đồng bộ và khả năng chỉnh Bass/Treble tiện cho chơi game, giải trí.', N'Logitech G560 là bộ loa 2.1 dành cho người dùng PC muốn nâng cấp trải nghiệm âm thanh lẫn hiệu ứng ánh sáng trên bàn máy. Sản phẩm hỗ trợ Bluetooth 4.1, LED RGB và cho phép tinh chỉnh âm sắc để phù hợp nhu cầu chơi game, xem phim hoặc nghe nhạc hằng ngày. Đây là lựa chọn hợp lý cho góc máy gaming hoặc desktop giải trí tại nhà.', N'/uploads/products/speaker/logitech-g560/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (123, N'SPK-RAZER-NOMMO-V2', N'Loa Razer Nommo V2', N'loa-razer-nommo-v2', 16, 29, CAST(6990000.00 AS Decimal(18, 2)), CAST(6100000.00 AS Decimal(18, 2)), 108, 0, N'Loa Razer Nommo V2 hỗ trợ Bluetooth 5.3, THX Spatial Audio, LED RGB và độ chi tiết âm thanh tốt cho gaming cao cấp.', N'Razer Nommo V2 là bộ loa gaming hướng đến người dùng cần âm thanh mạnh, rõ và dễ đồng bộ với hệ sinh thái Razer. Bluetooth 5.3 cùng công nghệ THX Spatial Audio giúp tăng cảm giác không gian khi chơi game, xem phim hoặc nghe nhạc. Thiết kế hiện đại, màu đen và hiệu ứng RGB khiến sản phẩm phù hợp cho các bộ bàn máy cao cấp.', N'/uploads/products/speaker/razer-nommo-v2/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (124, N'SPK-THONETVANDER-KUMPEL20-BLACK', N'Loa Thonet & Vander Kumpel 2.0 Black', N'loa-thonet-vander-kumpel-2-0-black', 16, 42, CAST(2990000.00 AS Decimal(18, 2)), NULL, 114, 0, N'Loa Thonet & Vander Kumpel 2.0 Black hỗ trợ Bluetooth 5.0, chỉnh Bass/Treble và phù hợp không gian làm việc, giải trí gọn gàng.', N'Thonet & Vander Kumpel 2.0 Black là mẫu loa desktop thiết kế gọn, nhấn mạnh sự cân bằng giữa thẩm mỹ và chất âm sử dụng hằng ngày. Sản phẩm hỗ trợ Bluetooth 5.0, có chỉnh Bass/Treble và giữ phong cách màu Black phù hợp nhiều góc làm việc hoặc giải trí. Đây là lựa chọn đáng cân nhắc cho người dùng thích bộ loa 2.0 đơn giản nhưng vẫn có cá tính riêng.', N'/uploads/products/speaker/thonet-vander-kumpel-2-0-black/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (125, N'SPK-RAZER-LEVIATHAN-V2X', N'Loa Razer Leviathan V2 X', N'loa-razer-leviathan-v2-x', 16, 29, CAST(3990000.00 AS Decimal(18, 2)), CAST(2490000.00 AS Decimal(18, 2)), 112, 0, N'Soundbar Razer Leviathan V2 X nhỏ gọn, THX Spatial Audio, Bluetooth 5.0 và LED RGB, phù hợp cho bàn máy gọn.', N'Razer Leviathan V2 X là mẫu soundbar dành cho game thủ cần thiết kế gọn gàng nhưng vẫn có chất âm mạnh và hiện đại. Bluetooth 5.0, THX Spatial Audio và LED RGB giúp sản phẩm nổi bật trên các góc máy setup tối giản hoặc gaming. Đây là lựa chọn phù hợp cho người dùng ưu tiên tiết kiệm không gian mà vẫn muốn trải nghiệm âm thanh sinh động.', N'/uploads/products/speaker/razer-leviathan-v2-x/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (126, N'SPK-RAZER-LEVIATHAN-V2', N'Loa Razer Leviathan V2', N'loa-razer-leviathan-v2', 16, 29, CAST(6990000.00 AS Decimal(18, 2)), CAST(5790000.00 AS Decimal(18, 2)), 107, 0, N'Loa soundbar Razer Leviathan V2 có Bluetooth 5.2, THX Spatial Audio, LED RGB và tinh chỉnh EQ 10 băng tần qua Synapse.', N'Razer Leviathan V2 là soundbar gaming cao cấp dành cho người dùng cần âm thanh mạnh, hiện đại và dễ tinh chỉnh theo sở thích. Công nghệ THX Spatial Audio, Bluetooth 5.2 và LED RGB giúp sản phẩm phù hợp cả chơi game lẫn giải trí đa phương tiện. Tính năng tùy chỉnh EQ 10 băng tần qua Razer Synapse là điểm cộng lớn cho người dùng thích cá nhân hóa trải nghiệm âm thanh.', N'/uploads/products/speaker/razer-leviathan-v2/thumb.jpg', 12, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (127, N'PCB-GVN-ROG-MIKU-9800X3D-5080', N'PC GVN X ASUS ROG HATSUNE MIKU EDITION (AMD Ryzen 7 9800X3D/VGA RTX 5080)', N'pc-gvn-x-asus-rog-hatsune-miku-edition-amd-ryzen-7-9800x3d-vga-rtx-5080', 17, 43, CAST(139640000.00 AS Decimal(18, 2)), CAST(128990000.00 AS Decimal(18, 2)), 102, 0, N'PC bộ GVN bản collab ASUS ROG Hatsune Miku với Ryzen 7 9800X3D, RAM 64GB, SSD 1TB và RTX 5080 16GB.', N'Đây là cấu hình PC bộ cao cấp dành cho game thủ và người dùng đòi hỏi hiệu năng hàng đầu ở độ phân giải 2K/4K. Bộ máy nổi bật nhờ thiết kế collab ASUS ROG Hatsune Miku cùng Ryzen 7 9800X3D, mainboard X870E, RAM 64GB và card RTX 5080 16GB. Sản phẩm phù hợp cho gaming cao cấp, stream, sáng tạo nội dung và trưng bày setup độc đáo.', N'/uploads/products/pc-build/gvn-rog-hatsune-miku-9800x3d-rtx5080/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (128, N'PCB-GVN-I7-14700F-RTX3050', N'PC GVN Intel i7-14700F/VGA RTX 3050', N'pc-gvn-intel-i7-14700f-vga-rtx-3050', 17, 43, CAST(33120000.00 AS Decimal(18, 2)), CAST(31590000.00 AS Decimal(18, 2)), 106, 0, N'PC bộ GVN dùng Intel Core i7-14700F, RTX 3050 6GB, RAM 16GB và SSD 512GB cho gaming phổ thông lẫn làm việc.', N'PC GVN Intel i7-14700F / RTX 3050 là cấu hình cân bằng cho người dùng cần một bộ máy sẵn sàng để học tập, làm việc và chơi game eSports. CPU Intel Core i7-14700F mang lại hiệu năng đa nhiệm tốt, trong khi RTX 3050 6GB đáp ứng ổn các tựa game online và dựng hình cơ bản. Đây là lựa chọn hợp lý cho người dùng muốn đầu tư một cấu hình desktop ổn định, dễ nâng cấp về sau.', N'/uploads/products/pc-build/gvn-i7-14700f-rtx3050/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (129, N'PCB-GVN-I5-14400F-RTX5060TI', N'PC GVN Intel i5-14400F/VGA RTX 5060 Ti', N'pc-gvn-intel-i5-14400f-vga-rtx-5060-ti', 17, 43, CAST(28580000.00 AS Decimal(18, 2)), CAST(25990000.00 AS Decimal(18, 2)), 107, 0, N'PC bộ GVN Intel Core i5-14400F, RTX 5060 Ti 8GB, RAM 8GB và SSD 512GB hướng đến gaming 1080p/2K.', N'Cấu hình này phù hợp cho người dùng ưu tiên chơi game hiện đại ở thiết lập tốt với chi phí hợp lý. Intel Core i5-14400F kết hợp RTX 5060 Ti 8GB mang lại hiệu năng tốt cho gaming, sáng tạo nội dung cơ bản và nhu cầu sử dụng dài hạn. Đây là bộ PC sẵn sàng để nâng cấp RAM hoặc dung lượng lưu trữ khi cần.', N'/uploads/products/pc-build/gvn-i5-14400f-rtx5060ti/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (130, N'PCB-GVN-R5-5600X-RX7600', N'PC GVN AMD R5-5600X/VGA RX 7600', N'pc-gvn-amd-r5-5600x-vga-rx-7600', 17, 43, CAST(23320000.00 AS Decimal(18, 2)), CAST(21990000.00 AS Decimal(18, 2)), 99, 10, N'PC bộ GVN Ryzen 5 5600X, Radeon RX 7600 8GB, RAM 8GB và SSD 256GB dành cho gaming phổ thông.', N'PC GVN AMD R5-5600X / RX 7600 là lựa chọn tiết kiệm cho game thủ cần bộ máy desktop có thể chơi tốt nhiều tựa game phổ biến ở độ phân giải Full HD. Ryzen 5 5600X vẫn đáp ứng tốt nhu cầu gaming và làm việc hằng ngày, trong khi RX 7600 8GB phù hợp với các tựa game AAA ở mức thiết lập hợp lý. Bộ máy phù hợp để nâng cấp thêm RAM hoặc SSD để mở rộng hiệu năng sử dụng lâu dài.', N'/uploads/products/pc-build/gvn-r5-5600x-rx7600/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (131, N'PCB-GVN-U5-225F-ARCB580', N'PC GVN Intel Ultra 5 225F/VGA ARC B580 (DDR5)', N'pc-gvn-intel-ultra-5-225f-vga-arc-b580-ddr5', 17, 43, CAST(30020000.00 AS Decimal(18, 2)), CAST(28490000.00 AS Decimal(18, 2)), 107, 1, N'PC bộ GVN dùng Intel Core Ultra 5 225F, Intel Arc B580 12GB, RAM 16GB DDR5 và SSD 500GB.', N'Bộ PC này hướng đến người dùng muốn trải nghiệm nền tảng Intel Core Ultra mới cùng card đồ họa Intel Arc B580 12GB. Cấu hình phù hợp cho gaming phổ thông, học tập, làm việc đa nhiệm và các nhu cầu sáng tạo nội dung cơ bản. Việc dùng RAM DDR5 và mainboard B860M giúp hệ thống có nền tảng mới, gọn gàng và dễ đồng bộ cho nhu cầu nâng cấp sau này.', N'/uploads/products/pc-build/gvn-ultra5-225f-arc-b580-ddr5/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (132, N'PCB-GVN-U7-265F-RTX5080', N'PC GVN Intel Core Ultra 7 265F/VGA RTX 5080', N'pc-gvn-intel-core-ultra-7-265f-vga-rtx-5080', 17, 43, CAST(77820000.00 AS Decimal(18, 2)), CAST(76590000.00 AS Decimal(18, 2)), 103, 0, N'PC bộ GVN Core Ultra 7 265F, RTX 5080 16GB, RAM 16GB và SSD 1TB dành cho gaming cao cấp.', N'PC GVN Intel Core Ultra 7 265F / RTX 5080 là cấu hình mạnh hướng đến game thủ và người dùng cần hiệu năng desktop cao cho nhiều tác vụ nặng. Hệ thống sở hữu card RTX 5080 16GB, SSD 1TB và nền tảng mainboard Z890, đáp ứng tốt nhu cầu chơi game 2K/4K, sáng tạo nội dung và làm việc chuyên sâu. Đây là bộ máy phù hợp cho người dùng muốn lên thẳng phân khúc cao cấp ngay từ đầu.', N'/uploads/products/pc-build/gvn-ultra7-265f-rtx5080/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (133, N'PCB-GVN-U7-265F-RTX5070', N'PC GVN Intel Core Ultra 7 265F/VGA RTX 5070', N'pc-gvn-intel-core-ultra-7-265f-vga-rtx-5070', 17, 43, CAST(58120000.00 AS Decimal(18, 2)), CAST(57690000.00 AS Decimal(18, 2)), 104, 0, N'PC bộ GVN Core Ultra 7 265F, RTX 5070, RAM 16GB và SSD 512GB cân bằng giữa hiệu năng cao và chi phí.', N'Cấu hình này hướng tới người dùng cần hiệu năng gaming mạnh nhưng vẫn muốn tối ưu ngân sách hơn so với nhóm RTX 5080. Intel Core Ultra 7 265F kết hợp RTX 5070 đủ sức chơi tốt các tựa game hiện đại và xử lý công việc sáng tạo nội dung ở mức rất tốt. Đây là lựa chọn phù hợp cho game thủ muốn hiệu năng cao, nền tảng mới và khả năng nâng cấp lâu dài.', N'/uploads/products/pc-build/gvn-ultra7-265f-rtx5070/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (134, N'PCB-GVN-R7-9800X3D-RTX5080-MSI', N'PC GVN AMD R7-9800X3D/VGA RTX 5080 (Powered by MSI)', N'pc-gvn-amd-r7-9800x3d-vga-rtx-5080-powered-by-msi', 17, 43, CAST(90720000.00 AS Decimal(18, 2)), CAST(88880000.00 AS Decimal(18, 2)), 98, 5, N'PC bộ GVN Powered by MSI với Ryzen 7 9800X3D, RTX 5080, RAM 32GB và SSD 1TB cho gaming flagship.', N'PC GVN AMD R7-9800X3D / RTX 5080 Powered by MSI là bộ máy cao cấp tập trung vào hiệu năng gaming hàng đầu và độ ổn định hệ thống. Ryzen 7 9800X3D kết hợp RTX 5080 mang lại sức mạnh phù hợp cho chơi game 2K/4K, stream và sáng tạo nội dung nặng. Đây là lựa chọn nổi bật cho người dùng thích cấu hình mạnh, hệ linh kiện đồng bộ và trải nghiệm desktop cao cấp.', N'/uploads/products/pc-build/gvn-r7-9800x3d-rtx5080-powered-by-msi/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
INSERT [dbo].[Products] ([Id], [SKU], [Name], [Slug], [CategoryId], [BrandId], [Price], [DiscountPrice], [StockQuantity], [SoldQuantity], [ShortDescription], [Description], [ThumbnailUrl], [WarrantyMonths], [IsFeatured], [IsActive], [CreatedAt], [UpdatedAt]) VALUES (135, N'PCB-GVN-I7-14700F-RTX5080', N'PC GVN Intel i7-14700F/VGA RTX 5080', N'pc-gvn-intel-i7-14700f-vga-rtx-5080', 17, 43, CAST(79420000.00 AS Decimal(18, 2)), CAST(77490000.00 AS Decimal(18, 2)), 103, 0, N'PC bộ GVN Intel Core i7-14700F, RTX 5080, RAM 32GB và SSD 1TB hướng đến gaming, render và đa nhiệm nặng.', N'PC GVN Intel i7-14700F / RTX 5080 phù hợp cho người dùng cần sức mạnh đồ họa rất cao nhưng vẫn ưu tiên CPU Intel quen thuộc cho làm việc và giải trí. Cấu hình gồm 32GB RAM, SSD 1TB và card RTX 5080 đáp ứng tốt nhu cầu chơi game nặng, dựng video, stream và xử lý đa nhiệm. Đây là bộ máy cao cấp phù hợp cho game thủ hoặc người dùng sáng tạo nội dung bán chuyên đến chuyên nghiệp.', N'/uploads/products/pc-build/gvn-i7-14700f-rtx5080/thumb.jpg', 36, 0, 1, CAST(N'2026-04-05T22:10:56.8232570' AS DateTime2), NULL)
