CREATE   PROCEDURE [dbo].[sp_Report_PaymentMethodSummary]
    @DateFrom DATETIME2(7) = NULL,
    @DateTo   DATETIME2(7) = NULL
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        P.PaymentMethod,
        P.PaymentStatus,
        COUNT(*) AS TotalPayments,
        CAST(ISNULL(SUM(P.Amount), 0) AS DECIMAL(18,2)) AS TotalAmount
